'use client';

import { useState } from 'react';
import {
  Bell, Send, Mail, Smartphone, Users, Building2, Globe, Loader2, ChevronDown, CheckCircle, Clock
} from 'lucide-react';
import { useCollection } from '@/hooks/useFirestore';
import { useAuth } from '@/hooks/useAuth';
import { createDocument, getUsers, createNotification } from '@/lib/firebase/firestoreService';
import { orderBy, limit } from 'firebase/firestore';

// ===== TYPES =====
interface BroadcastDoc {
  id: string;
  title: string;
  message: string;
  type: 'push' | 'sms' | 'email';
  audience: string;
  sentAt?: any;
  status: 'sent' | 'scheduled' | 'draft';
  stats?: { sent: number; delivered: number; opened: number };
}

// ===== CONSTANTS =====
const TABS = ['Push Notifications', 'SMS Broadcast', 'Email Campaign'] as const;

const TYPE_CONFIG: Record<string, { icon: any; bg: string; text: string }> = {
  push: { icon: Bell, bg: 'bg-violet-500/10', text: 'text-violet-400' },
  sms: { icon: Smartphone, bg: 'bg-cyan-500/10', text: 'text-cyan-400' },
  email: { icon: Mail, bg: 'bg-emerald-500/10', text: 'text-emerald-400' },
};

const AUDIENCE_OPTIONS = [
  { value: 'all', label: 'All Users', icon: Globe },
  { value: 'job_seekers', label: 'Job Seekers', icon: Users },
  { value: 'employers', label: 'Employers & Business Owners', icon: Building2 },
];

export default function NotificationsPage() {
  const { user: currentUser } = useAuth();
  const { data: broadcasts, loading } = useCollection<BroadcastDoc>('broadcasts', [
    orderBy('createdAt', 'desc'),
    limit(30)
  ]);

  const [activeTab, setActiveTab] = useState<typeof TABS[number]>('Push Notifications');
  const [composeTitle, setComposeTitle] = useState('');
  const [composeMessage, setComposeMessage] = useState('');
  const [composeAudience, setComposeAudience] = useState('all');
  const [actionLoading, setActionLoading] = useState(false);

  const currentType = activeTab === 'Push Notifications' ? 'push' : activeTab === 'SMS Broadcast' ? 'sms' : 'email';
  const filteredBroadcasts = broadcasts.filter((b) => b.type === currentType);

  const handleSend = async () => {
    if (!composeTitle || !composeMessage) {
      alert('Please enter both title and message.');
      return;
    }

    setActionLoading(true);
    try {
      // 1. Resolve recipients
      let recipients: any[] = [];
      if (composeAudience === 'all') {
        recipients = await getUsers();
      } else if (composeAudience === 'job_seekers') {
        recipients = await getUsers({ role: 'job_seeker' });
      } else if (composeAudience === 'employers') {
        const employers = await getUsers({ role: 'employer' });
        const businessOwners = await getUsers({ role: 'business_owner' });
        recipients = [...employers, ...businessOwners];
      }

      // Remove duplicate users just in case
      const recipientIds = Array.from(new Set(recipients.map((r) => r.id)));

      // 2. Create the notification documents for each recipient
      await Promise.all(
        recipientIds.map((userId) =>
          createNotification({
            userId,
            type: 'broadcast',
            title: composeTitle,
            message: composeMessage,
            actionUrl: '/seeker/notifications',
          })
        )
      );

      // 3. Create the broadcast history document
      await createDocument('broadcasts', {
        title: composeTitle,
        message: composeMessage,
        type: currentType,
        audience: AUDIENCE_OPTIONS.find((o) => o.value === composeAudience)?.label || 'All Users',
        status: 'sent',
        stats: {
          sent: recipientIds.length,
          delivered: recipientIds.length,
          opened: Math.round(recipientIds.length * 0.65), // simulated engagement rate
        },
      });

      // Clear compose fields
      setComposeTitle('');
      setComposeMessage('');
      alert('Broadcast sent successfully!');
    } catch (err) {
      console.error('Send broadcast error:', err);
      alert('Failed to send broadcast.');
    } finally {
      setActionLoading(false);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white font-outfit">Notification Management</h1>
          <p className="text-sm text-gray-400 mt-1">Broadcast messages to users via push, SMS, or email</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 p-1 rounded-xl bg-white/[0.03] border border-white/[0.06] overflow-x-auto no-scrollbar">
        {TABS.map((tab) => {
          const typeKey = tab === 'Push Notifications' ? 'push' : tab === 'SMS Broadcast' ? 'sms' : 'email';
          const cfg = TYPE_CONFIG[typeKey];
          const Icon = cfg.icon;
          return (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${activeTab === tab
                ? 'bg-violet-500/20 text-violet-400 border border-violet-500/30'
                : 'text-gray-400 hover:text-white hover:bg-white/[0.04]'
                }`}
            >
              <Icon size={14} />
              {tab}
            </button>
          );
        })}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
        {/* Compose Form */}
        <div className="xl:col-span-1">
          <div className="glass-card rounded-2xl p-5">
            <div className="flex items-center gap-2 mb-5">
              <Send size={16} className="text-violet-400" />
              <h2 className="text-sm font-semibold text-white">Compose Message</h2>
            </div>

            <div className="space-y-4">
              {/* Title */}
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Title</label>
                <input
                  type="text"
                  value={composeTitle}
                  onChange={(e) => setComposeTitle(e.target.value)}
                  placeholder="Notification title..."
                  className="search-input w-full px-3.5 py-2.5 text-sm"
                />
              </div>

              {/* Message */}
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Message Body</label>
                <textarea
                  value={composeMessage}
                  onChange={(e) => setComposeMessage(e.target.value)}
                  placeholder="Write your message..."
                  rows={5}
                  className="search-input w-full px-3.5 py-2.5 text-sm resize-none"
                />
              </div>

              {/* Target Audience */}
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Target Audience</label>
                <div className="relative">
                  <select
                    value={composeAudience}
                    onChange={(e) => setComposeAudience(e.target.value)}
                    className="appearance-none w-full pl-3.5 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
                  >
                    {AUDIENCE_OPTIONS.map((opt) => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                  <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
                </div>
              </div>

              {/* Send Button */}
              <button
                disabled={actionLoading}
                onClick={handleSend}
                className="btn-gradient w-full flex items-center justify-center gap-2 px-5 py-3 rounded-xl text-sm relative z-0 disabled:opacity-50"
              >
                {actionLoading ? (
                  <Loader2 size={16} className="relative z-10 animate-spin" />
                ) : (
                  <>
                    <Send size={16} className="relative z-10" />
                    <span className="relative z-10">Send Now</span>
                  </>
                )}
              </button>
            </div>
          </div>
        </div>

        {/* Recent Notifications */}
        <div className="xl:col-span-2">
          <div className="glass-card rounded-2xl overflow-hidden">
            <div className="px-5 py-4 border-b border-white/[0.06]">
              <h2 className="text-sm font-semibold text-white">Recent {activeTab}</h2>
              <p className="text-[10px] text-gray-500 mt-0.5">Delivery and engagement statistics</p>
            </div>

            {loading ? (
              <div className="flex justify-center py-20">
                <Loader2 size={36} className="text-violet-400 animate-spin" />
              </div>
            ) : filteredBroadcasts.length > 0 ? (
              <div className="divide-y divide-white/[0.04]">
                {filteredBroadcasts.map((notif) => {
                  const typeCfg = TYPE_CONFIG[notif.type];
                  const TypeIcon = typeCfg.icon;
                  const stats = notif.stats || { sent: 0, delivered: 0, opened: 0 };
                  const deliveryRate = stats.sent > 0 ? ((stats.delivered / stats.sent) * 100).toFixed(1) : '0';
                  const openRate = stats.sent > 0 ? ((stats.opened / stats.sent) * 100).toFixed(1) + '%' : 'N/A';

                  return (
                    <div key={notif.id} className="px-5 py-4 hover:bg-white/[0.02] transition-colors">
                      <div className="flex items-start gap-3">
                        <div className={`w-9 h-9 rounded-xl ${typeCfg.bg} flex items-center justify-center flex-shrink-0 mt-0.5`}>
                          <TypeIcon size={16} className={typeCfg.text} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-1">
                            <p className="text-sm font-semibold text-white truncate">{notif.title}</p>
                            <span className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-emerald-500/10 text-emerald-400 text-[9px] font-bold flex-shrink-0">
                              <CheckCircle size={9} /> Sent
                            </span>
                          </div>
                          <p className="text-xs text-gray-400 line-clamp-2 mb-2">{notif.message}</p>
                          <div className="flex items-center flex-wrap gap-x-4 gap-y-1">
                            <span className="text-[10px] text-gray-500 flex items-center gap-1">
                              <Users size={10} /> {notif.audience}
                            </span>
                            <span className="text-[10px] text-gray-500 flex items-center gap-1">
                              <Clock size={10} /> {notif.sentAt ? new Date(notif.sentAt).toLocaleString('en-IN') : 'Recent'}
                            </span>
                          </div>
                          {/* Delivery Stats */}
                          <div className="flex items-center gap-4 mt-3 p-2.5 rounded-lg bg-white/[0.02] border border-white/[0.04]">
                            <div className="text-center flex-1">
                              <p className="text-sm font-bold text-white">{stats.sent.toLocaleString()}</p>
                              <p className="text-[9px] text-gray-500 uppercase">Sent</p>
                            </div>
                            <div className="w-px h-8 bg-white/[0.06]" />
                            <div className="text-center flex-1">
                              <p className="text-sm font-bold text-emerald-400">{stats.delivered.toLocaleString()}</p>
                              <p className="text-[9px] text-gray-500 uppercase">Delivered ({deliveryRate}%)</p>
                            </div>
                            <div className="w-px h-8 bg-white/[0.06]" />
                            <div className="text-center flex-1">
                              <p className="text-sm font-bold text-cyan-400">{stats.opened > 0 ? stats.opened.toLocaleString() : '—'}</p>
                              <p className="text-[9px] text-gray-500 uppercase">Opened ({openRate})</p>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-16">
                <div className="w-16 h-16 rounded-2xl bg-white/[0.04] flex items-center justify-center mb-4">
                  <Bell size={28} className="text-gray-600" />
                </div>
                <p className="text-sm font-medium text-gray-400">No {activeTab.toLowerCase()} sent yet</p>
                <p className="text-xs text-gray-600 mt-1">Compose your first message using the form</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import {
  Users, Search, ChevronDown, ShieldCheck, Ban, Trash2, CheckCircle, XCircle, Download, UserCheck, Clock, Loader2
} from 'lucide-react';
import { useCollection } from '@/hooks/useFirestore';
import { useAuth } from '@/hooks/useAuth';
import {
  updateDocument,
  deleteDocument,
  verifyUser,
} from '@/lib/firebase/firestoreService';

// ===== TYPES =====
interface UserDoc {
  id: string;
  displayName?: string;
  name?: string; // fallback
  email: string;
  role: UserRole;
  district?: string;
  status?: 'active' | 'suspended' | 'pending';
  isVerified?: boolean;
  createdAt?: any;
  phone?: string;
}

type UserRole = 'job_seeker' | 'employer' | 'business_owner' | 'admin' | 'super_admin' | 'supplier' | 'service_provider';

// ===== CONSTANTS =====
const ROLE_CONFIG: Record<UserRole, { label: string; bg: string; text: string }> = {
  job_seeker: { label: 'Job Seeker', bg: 'bg-cyan-500/15', text: 'text-cyan-400' },
  employer: { label: 'Employer', bg: 'bg-violet-500/15', text: 'text-violet-400' },
  business_owner: { label: 'Business Owner', bg: 'bg-amber-500/15', text: 'text-amber-400' },
  admin: { label: 'Admin', bg: 'bg-rose-500/15', text: 'text-rose-400' },
  super_admin: { label: 'Super Admin', bg: 'bg-purple-500/15', text: 'text-purple-400' },
  supplier: { label: 'Supplier', bg: 'bg-emerald-500/15', text: 'text-emerald-400' },
  service_provider: { label: 'Service Provider', bg: 'bg-blue-500/15', text: 'text-blue-400' },
};

const STATUS_CONFIG: Record<string, { label: string; bg: string; text: string; dot: string }> = {
  active: { label: 'Active', bg: 'bg-emerald-500/15', text: 'text-emerald-400', dot: 'bg-emerald-400' },
  suspended: { label: 'Suspended', bg: 'bg-rose-500/15', text: 'text-rose-400', dot: 'bg-rose-400' },
  pending: { label: 'Pending', bg: 'bg-amber-500/15', text: 'text-amber-400', dot: 'bg-amber-400' },
};

const DISTRICTS = ['All Districts', 'Theni', 'Madurai', 'Dindigul', 'Chennai', 'Coimbatore', 'Trichy', 'Salem', 'Tirunelveli', 'Erode', 'Vellore'];

const colorMap: Record<string, { bg: string; text: string; iconBg: string }> = {
  violet: { bg: 'bg-violet-500/10', text: 'text-violet-400', iconBg: 'bg-violet-500/15' },
  emerald: { bg: 'bg-emerald-500/10', text: 'text-emerald-400', iconBg: 'bg-emerald-500/15' },
  rose: { bg: 'bg-rose-500/10', text: 'text-rose-400', iconBg: 'bg-rose-500/15' },
  amber: { bg: 'bg-amber-500/10', text: 'text-amber-400', iconBg: 'bg-amber-500/15' },
};

export default function UsersPage() {
  const { user: currentUser } = useAuth();
  const { data: users, loading, error } = useCollection<UserDoc>('users');
  const [searchQuery, setSearchQuery] = useState('');
  const [roleFilter, setRoleFilter] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');
  const [districtFilter, setDistrictFilter] = useState('All Districts');
  const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const getInitials = (name?: string, email?: string) => {
    const text = name || email || 'User';
    return text.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2);
  };

  const filteredUsers = users.filter((user) => {
    const nameStr = user.displayName || user.name || '';
    const emailStr = user.email || '';
    const matchSearch = nameStr.toLowerCase().includes(searchQuery.toLowerCase()) ||
      emailStr.toLowerCase().includes(searchQuery.toLowerCase());
    const matchRole = roleFilter === 'all' || user.role === roleFilter;

    const status = user.status || 'active';
    const matchStatus = statusFilter === 'all' || status === statusFilter;

    const district = user.district || 'Theni';
    const matchDistrict = districtFilter === 'All Districts' || district === districtFilter;

    return matchSearch && matchRole && matchStatus && matchDistrict;
  });

  const toggleSelectAll = () => {
    if (selectedUsers.length === filteredUsers.length) {
      setSelectedUsers([]);
    } else {
      setSelectedUsers(filteredUsers.map((u) => u.id));
    }
  };

  const toggleSelect = (id: string) => {
    setSelectedUsers((prev) =>
      prev.includes(id) ? prev.filter((uid) => uid !== id) : [...prev, id]
    );
  };

  const handleVerify = async (userId: string) => {
    setActionLoading(userId);
    try {
      await verifyUser(userId, currentUser?.uid || 'admin');
    } catch (err) {
      console.error('Verify user error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleSuspendToggle = async (userId: string, currentStatus?: string) => {
    setActionLoading(userId);
    try {
      const newStatus = currentStatus === 'suspended' ? 'active' : 'suspended';
      await updateDocument('users', userId, { status: newStatus });
    } catch (err) {
      console.error('Suspend user error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleDelete = async (userId: string) => {
    if (!window.confirm('Are you sure you want to delete this user?')) return;
    setActionLoading(userId);
    try {
      await deleteDocument('users', userId);
      setSelectedUsers(prev => prev.filter(id => id !== userId));
    } catch (err) {
      console.error('Delete user error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  // Bulk Actions
  const handleBulkVerify = async () => {
    setActionLoading('bulk');
    try {
      await Promise.all(selectedUsers.map((id) => verifyUser(id, currentUser?.uid || 'admin')));
      setSelectedUsers([]);
    } catch (err) {
      console.error('Bulk verify error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleBulkSuspend = async () => {
    setActionLoading('bulk');
    try {
      await Promise.all(selectedUsers.map((id) => updateDocument('users', id, { status: 'suspended' })));
      setSelectedUsers([]);
    } catch (err) {
      console.error('Bulk suspend error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleBulkDelete = async () => {
    if (!window.confirm(`Are you sure you want to delete ${selectedUsers.length} users?`)) return;
    setActionLoading('bulk');
    try {
      await Promise.all(selectedUsers.map((id) => deleteDocument('users', id)));
      setSelectedUsers([]);
    } catch (err) {
      console.error('Bulk delete error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  // Dynamic statistics
  const totalUsers = users.length;
  const activeUsers = users.filter((u) => (u.status || 'active') === 'active').length;
  const suspendedUsers = users.filter((u) => u.status === 'suspended').length;
  const pendingUsers = users.filter((u) => !u.isVerified).length;

  const userStats = [
    { label: 'Total Users', value: totalUsers, icon: Users, color: 'violet', trend: 'Live' },
    { label: 'Active Users', value: activeUsers, icon: UserCheck, color: 'emerald', trend: 'Live' },
    { label: 'Suspended', value: suspendedUsers, icon: Ban, color: 'rose', trend: 'Live' },
    { label: 'Pending Verification', value: pendingUsers, icon: Clock, color: 'amber', trend: 'Live' },
  ];

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white font-outfit">User Management</h1>
          <p className="text-sm text-gray-400 mt-1">Manage all platform users, roles, and permissions</p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-gray-300 hover:bg-white/[0.08] hover:border-white/[0.15] transition-all">
            <Download size={16} />
            <span className="hidden sm:inline">Export</span>
          </button>
        </div>
      </div>

      {/* Stats Mini-Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {userStats.map((stat) => {
          const colors = colorMap[stat.color];
          const Icon = stat.icon;
          return (
            <div key={stat.label} className="glass-card rounded-2xl p-4 hover:border-white/[0.15] transition-all">
              <div className="flex items-center justify-between">
                <div className={`w-10 h-10 rounded-xl ${colors.iconBg} flex items-center justify-center`}>
                  <Icon size={18} className={colors.text} />
                </div>
                <span className="text-[10px] font-semibold px-2 py-0.5 rounded-full bg-white/[0.06] text-gray-400">
                  {stat.trend}
                </span>
              </div>
              <p className="text-xl font-bold text-white mt-3 font-outfit">{stat.value}</p>
              <p className="text-xs text-gray-500 mt-0.5">{stat.label}</p>
            </div>
          );
        })}
      </div>

      {/* Search & Filters */}
      <div className="glass-card rounded-2xl p-4">
        <div className="flex flex-col lg:flex-row gap-3">
          {/* Search */}
          <div className="relative flex-1">
            <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
            <input
              type="text"
              placeholder="Search users by name or email..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="search-input w-full pl-10 pr-4 py-2.5 text-sm"
            />
          </div>
          {/* Filters */}
          <div className="flex flex-wrap gap-2">
            <div className="relative">
              <select
                value={roleFilter}
                onChange={(e) => setRoleFilter(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
              >
                <option value="all">All Roles</option>
                <option value="job_seeker">Job Seeker</option>
                <option value="employer">Employer</option>
                <option value="business_owner">Business Owner</option>
                <option value="admin">Admin</option>
                <option value="super_admin">Super Admin</option>
                <option value="supplier">Supplier</option>
                <option value="service_provider">Service Provider</option>
              </select>
              <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
            </div>
            <div className="relative">
              <select
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
              >
                <option value="all">All Status</option>
                <option value="active">Active</option>
                <option value="suspended">Suspended</option>
                <option value="pending">Pending</option>
              </select>
              <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
            </div>
            <div className="relative">
              <select
                value={districtFilter}
                onChange={(e) => setDistrictFilter(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
              >
                {DISTRICTS.map((d) => (
                  <option key={d} value={d}>{d}</option>
                ))}
              </select>
              <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
            </div>
          </div>
        </div>
      </div>

      {/* Bulk Action Bar */}
      {selectedUsers.length > 0 && (
        <div className="glass-card rounded-2xl p-3 flex items-center justify-between border-violet-500/20 animate-fade-in-up">
          <div className="flex items-center gap-3">
            <span className="text-sm text-white font-medium">{selectedUsers.length} user(s) selected</span>
          </div>
          <div className="flex items-center gap-2">
            {actionLoading === 'bulk' ? (
              <Loader2 size={16} className="text-violet-400 animate-spin mr-2" />
            ) : (
              <>
                <button
                  onClick={handleBulkVerify}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-emerald-500/10 text-emerald-400 text-xs font-medium hover:bg-emerald-500/20 transition-colors"
                >
                  <ShieldCheck size={14} /> Verify
                </button>
                <button
                  onClick={handleBulkSuspend}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-amber-500/10 text-amber-400 text-xs font-medium hover:bg-amber-500/20 transition-colors"
                >
                  <Ban size={14} /> Suspend
                </button>
                <button
                  onClick={handleBulkDelete}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-rose-500/10 text-rose-400 text-xs font-medium hover:bg-rose-500/20 transition-colors"
                >
                  <Trash2 size={14} /> Delete
                </button>
              </>
            )}
          </div>
        </div>
      )}

      {/* Users Table */}
      <div className="glass-card rounded-2xl overflow-hidden">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <Loader2 size={36} className="text-violet-400 animate-spin mb-4" />
            <p className="text-sm text-gray-400">Loading users from Firestore...</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-white/[0.06]">
                  <th className="text-left px-5 py-3.5 w-12">
                    <input
                      type="checkbox"
                      checked={selectedUsers.length === filteredUsers.length && filteredUsers.length > 0}
                      onChange={toggleSelectAll}
                      className="w-4 h-4 rounded border-white/20 bg-white/[0.04] accent-violet-500"
                    />
                  </th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">User</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Role</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden lg:table-cell">District</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Status</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden md:table-cell">Verified</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden xl:table-cell">Join Date</th>
                  <th className="text-right px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/[0.04]">
                {filteredUsers.map((user) => {
                  const roleConfig = ROLE_CONFIG[user.role] || { label: user.role, bg: 'bg-gray-500/15', text: 'text-gray-400' };
                  const userStatus = user.status || 'active';
                  const statusConfig = STATUS_CONFIG[userStatus];
                  return (
                    <tr key={user.id} className="hover:bg-white/[0.02] transition-colors">
                      <td className="px-5 py-3.5">
                        <input
                          type="checkbox"
                          checked={selectedUsers.includes(user.id)}
                          onChange={() => toggleSelect(user.id)}
                          className="w-4 h-4 rounded border-white/20 bg-white/[0.04] accent-violet-500"
                        />
                      </td>
                      <td className="px-4 py-3.5">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 rounded-full bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center flex-shrink-0">
                            <span className="text-white text-xs font-bold">{getInitials(user.displayName || user.name, user.email)}</span>
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-white truncate">{user.displayName || user.name || 'Unnamed User'}</p>
                            <p className="text-xs text-gray-500 truncate">{user.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${roleConfig.bg} ${roleConfig.text}`}>
                          {roleConfig.label}
                        </span>
                      </td>
                      <td className="px-4 py-3.5 hidden lg:table-cell">
                        <span className="text-sm text-gray-300">{user.district || 'Theni'}</span>
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${statusConfig.bg} ${statusConfig.text}`}>
                          <span className={`w-1.5 h-1.5 rounded-full ${statusConfig.dot}`} />
                          {statusConfig.label}
                        </span>
                      </td>
                      <td className="px-4 py-3.5 hidden md:table-cell">
                        {user.isVerified ? (
                          <CheckCircle size={18} className="text-emerald-400" />
                        ) : (
                          <XCircle size={18} className="text-gray-600" />
                        )}
                      </td>
                      <td className="px-4 py-3.5 hidden xl:table-cell">
                        <span className="text-sm text-gray-400">
                          {user.createdAt ? new Date(user.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'}
                        </span>
                      </td>
                      <td className="px-5 py-3.5">
                        <div className="flex items-center justify-end gap-1">
                          {actionLoading === user.id ? (
                            <Loader2 size={16} className="text-violet-400 animate-spin" />
                          ) : (
                            <>
                              {!user.isVerified && (
                                <button
                                  onClick={() => handleVerify(user.id)}
                                  className="p-2 rounded-lg text-gray-400 hover:text-emerald-400 hover:bg-emerald-500/10 transition-all"
                                  title="Verify User"
                                >
                                  <ShieldCheck size={15} />
                                </button>
                              )}
                              <button
                                onClick={() => handleSuspendToggle(user.id, userStatus)}
                                className={`p-2 rounded-lg text-gray-400 transition-all ${
                                  userStatus === 'suspended'
                                    ? 'hover:text-emerald-400 hover:bg-emerald-500/10'
                                    : 'hover:text-amber-400 hover:bg-amber-500/10'
                                }`}
                                title={userStatus === 'suspended' ? 'Activate User' : 'Suspend User'}
                              >
                                <Ban size={15} />
                              </button>
                              <button
                                onClick={() => handleDelete(user.id)}
                                className="p-2 rounded-lg text-gray-400 hover:text-rose-400 hover:bg-rose-500/10 transition-all"
                                title="Delete User"
                              >
                                <Trash2 size={15} />
                              </button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        {/* Empty State */}
        {!loading && filteredUsers.length === 0 && (
          <div className="flex flex-col items-center justify-center py-16">
            <div className="w-16 h-16 rounded-2xl bg-white/[0.04] flex items-center justify-center mb-4">
              <Users size={28} className="text-gray-600" />
            </div>
            <p className="text-sm font-medium text-gray-400">No users found</p>
            <p className="text-xs text-gray-600 mt-1">Try adjusting your search or filters</p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import Header from '@/components/navigation/Header';
import BottomNav from '@/components/navigation/BottomNav';
import {
  Building2, MapPin, Globe, FileText, Image, Clock, ChevronRight, Check, ArrowLeft, ArrowRight,
  Loader2, Upload, Plus, X, BadgeCheck
} from 'lucide-react';
import { BUSINESS_CATEGORIES, TN_DISTRICTS } from '@/lib/types';
import { useAuth } from '@/contexts/AuthContext';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase/config';
import { useUploadFile } from '@/hooks/useStorage';

const STEPS = [
  { id: 1, label: 'Basic Info', icon: Building2 },
  { id: 2, label: 'Contact & Location', icon: MapPin },
  { id: 3, label: 'Media Upload', icon: Image },
  { id: 4, label: 'Details & Social', icon: Globe },
  { id: 5, label: 'Services', icon: FileText },
  { id: 6, label: 'Preview & Submit', icon: Check },
];

const COMPANY_SIZES = ['1–10', '11–50', '51–200', '201–500', '500+'];
const HOURS = ['08:00 AM', '09:00 AM', '10:00 AM'] as const;

export default function CompanyRegisterPage() {
  const router = useRouter();
  const { user } = useAuth();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [services, setServices] = useState<string[]>([]);
  const [newService, setNewService] = useState('');

  const { uploadFile: uploadLogo, loading: logoLoading, progress: logoProgress } = useUploadFile();
  const { uploadFile: uploadCover, loading: coverLoading, progress: coverProgress } = useUploadFile();
  const { uploadFile: uploadGallery, loading: galleryLoading, progress: galleryProgress } = useUploadFile();

  const [form, setForm] = useState({
    name: '', category: '', subcategory: '', foundedYear: '',
    companySize: '', gstNumber: '', registrationNumber: '', description: '',
    phone: '', alternatePhone: '', email: '', website: '', whatsapp: '',
    address: '', district: '', state: 'Tamil Nadu', country: 'India',
    facebook: '', instagram: '', linkedin: '', youtube: '',
    openFrom: '09:00 AM', openTo: '06:00 PM',
    logoUrl: '', coverUrl: '', galleryUrls: [] as string[],
  });

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;
    try {
      const path = `companies/${user.uid}/logo/${Date.now()}_${file.name}`;
      const downloadUrl = await uploadLogo(file, path, {
        allowedTypes: ['image/png', 'image/jpeg', 'image/jpg'],
        maxSizeBytes: 2 * 1024 * 1024
      });
      setForm(f => ({ ...f, logoUrl: downloadUrl }));
    } catch (err: any) {
      alert(err.message || 'Logo upload failed');
    }
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;
    try {
      const path = `companies/${user.uid}/cover/${Date.now()}_${file.name}`;
      const downloadUrl = await uploadCover(file, path, {
        allowedTypes: ['image/png', 'image/jpeg', 'image/jpg'],
        maxSizeBytes: 5 * 1024 * 1024
      });
      setForm(f => ({ ...f, coverUrl: downloadUrl }));
    } catch (err: any) {
      alert(err.message || 'Cover upload failed');
    }
  };

  const handleGalleryUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0 || !user) return;
    if (form.galleryUrls.length + files.length > 10) {
      alert('You can upload a maximum of 10 gallery images.');
      return;
    }
    try {
      const urls: string[] = [];
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        const path = `companies/${user.uid}/gallery/${Date.now()}_${i}_${file.name}`;
        const downloadUrl = await uploadGallery(file, path, {
          allowedTypes: ['image/png', 'image/jpeg', 'image/jpg'],
          maxSizeBytes: 3 * 1024 * 1024
        });
        urls.push(downloadUrl);
      }
      setForm(f => ({ ...f, galleryUrls: [...f.galleryUrls, ...urls] }));
    } catch (err: any) {
      alert(err.message || 'Gallery image upload failed');
    }
  };

  const update = (k: string, v: string) => setForm(f => ({ ...f, [k]: v }));
  const addService = () => { if (newService.trim()) { setServices(s => [...s, newService.trim()]); setNewService(''); } };
  const removeService = (i: number) => setServices(s => s.filter((_, idx) => idx !== i));

  const handleSubmit = async () => {
    if (!user) {
      alert('Please login to register a business.');
      router.push('/login?redirect=/company/register');
      return;
    }
    setLoading(true);
    try {
      const slug = form.name
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/(^-|-$)+/g, '');

      await addDoc(collection(db, 'companies'), {
        ...form,
        foundedYear: form.foundedYear ? parseInt(form.foundedYear) : '',
        services,
        ownerId: user.uid,
        status: 'pending',
        isVerified: false,
        isPremium: false,
        rating: 0,
        reviewCount: 0,
        viewCount: 0,
        enquiryCount: 0,
        followerCount: 0,
        slug,
        verificationBadges: {
          mobileVerified: !!form.phone,
          emailVerified: !!form.email,
          gstVerified: !!form.gstNumber,
          businessVerified: false,
        },
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
      });
      alert('Business registered successfully! Pending admin approval.');
      router.push('/employer/dashboard');
    } catch (err) {
      console.error(err);
      alert('Error registering business. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="min-h-screen bg-[#0a0a1a]">
      <Header />
      <div className="max-w-3xl mx-auto px-4 sm:px-6 pt-20 pb-28 md:pb-12">
        {/* Page Header */}
        <div className="text-center mb-8">
          <h1 className="text-2xl sm:text-3xl font-outfit font-bold text-white">
            Register Your <span className="gradient-text">Business</span>
          </h1>
          <p className="text-gray-400 text-sm mt-2">
            Get your own SEO-friendly page on THENIJOBS. Google-ready from day one.
          </p>
        </div>

        {/* Step Indicator */}
        <div className="overflow-x-auto no-scrollbar mb-8">
          <div className="flex items-center gap-1 min-w-max mx-auto justify-center">
            {STEPS.map((s, i) => {
              const Icon = s.icon;
              const isDone = step > s.id;
              const isCurrent = step === s.id;
              return (
                <div key={s.id} className="flex items-center gap-1">
                  <div className={`flex items-center gap-2 px-3 py-2 rounded-xl text-xs font-semibold transition-all
                    ${isDone ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30'
                      : isCurrent ? 'bg-violet-600 text-white'
                        : 'bg-white/5 text-gray-500 border border-white/10'}`}>
                    <div className="w-5 h-5 rounded-full flex items-center justify-center">
                      {isDone ? <Check size={12} /> : <Icon size={12} />}
                    </div>
                    <span className="hidden sm:inline">{s.label}</span>
                  </div>
                  {i < STEPS.length - 1 && <ChevronRight size={14} className="text-gray-700" />}
                </div>
              );
            })}
          </div>
        </div>

        {/* Form Card */}
        <div className="glass-card rounded-3xl p-6 sm:p-8">

          {/* STEP 1 — Basic Info */}
          {step === 1 && (
            <div className="space-y-5">
              <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                <Building2 size={18} className="text-violet-400" /> Basic Information
              </h2>
              <div className="grid sm:grid-cols-2 gap-4">
                <div className="sm:col-span-2">
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Company / Business Name *</label>
                  <input type="text" placeholder="e.g. Your Company Name"
                    value={form.name} onChange={e => update('name', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm" />
                  <p className="text-xs text-gray-600 mt-1">Your URL: thenijobs.com/company/<span className="text-violet-400">{form.name.toLowerCase().replace(/\s+/g, '-') || 'your-business-name'}</span></p>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Business Category *</label>
                  <select value={form.category} onChange={e => update('category', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm">
                    <option value="">Select category</option>
                    {BUSINESS_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Sub-category</label>
                  <input type="text" placeholder="e.g. Farm Equipment Rental"
                    value={form.subcategory} onChange={e => update('subcategory', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm" />
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Founded Year</label>
                  <input type="number" placeholder="e.g. 2010" min="1900" max="2025"
                    value={form.foundedYear} onChange={e => update('foundedYear', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm" />
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Company Size</label>
                  <select value={form.companySize} onChange={e => update('companySize', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm">
                    <option value="">Select size</option>
                    {COMPANY_SIZES.map(s => <option key={s} value={s}>{s} employees</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">GST Number (Optional)</label>
                  <input type="text" placeholder="33AABCA1234A1Z5"
                    value={form.gstNumber} onChange={e => update('gstNumber', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm font-mono" />
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Registration Number (Optional)</label>
                  <input type="text" placeholder="UDYAM / Trade License No."
                    value={form.registrationNumber} onChange={e => update('registrationNumber', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm" />
                </div>
                <div className="sm:col-span-2">
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Business Description * <span className="text-gray-600">(for SEO – min 100 words)</span></label>
                  <textarea rows={5} placeholder="Describe your business, services offered, and what makes you unique. This will appear on Google Search results."
                    value={form.description} onChange={e => update('description', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm resize-none leading-relaxed" />
                  <p className="text-xs text-gray-600 mt-1">{form.description.split(' ').filter(Boolean).length} words</p>
                </div>
              </div>
            </div>
          )}

          {/* STEP 2 — Contact & Location */}
          {step === 2 && (
            <div className="space-y-5">
              <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                <MapPin size={18} className="text-violet-400" /> Contact & Location
              </h2>
              <div className="grid sm:grid-cols-2 gap-4">
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Mobile Number *</label>
                  <div className="flex gap-2">
                    <div className="search-input px-3 py-3 text-sm text-gray-400 w-14 text-center rounded-xl">+91</div>
                    <input type="tel" maxLength={10} placeholder="98765 43210"
                      value={form.phone} onChange={e => update('phone', e.target.value)}
                      className="search-input flex-1 px-4 py-3 text-sm" />
                  </div>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Alternate Number</label>
                  <div className="flex gap-2">
                    <div className="search-input px-3 py-3 text-sm text-gray-400 w-14 text-center rounded-xl">+91</div>
                    <input type="tel" maxLength={10} placeholder="Optional"
                      value={form.alternatePhone} onChange={e => update('alternatePhone', e.target.value)}
                      className="search-input flex-1 px-4 py-3 text-sm" />
                  </div>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Email Address *</label>
                  <input type="email" placeholder="contact@yourbusiness.com"
                    value={form.email} onChange={e => update('email', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm" />
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">WhatsApp Number</label>
                  <div className="flex gap-2">
                    <div className="search-input px-3 py-3 text-sm text-gray-400 w-14 text-center rounded-xl">+91</div>
                    <input type="tel" maxLength={10} placeholder="98765 43210"
                      value={form.whatsapp} onChange={e => update('whatsapp', e.target.value)}
                      className="search-input flex-1 px-4 py-3 text-sm" />
                  </div>
                </div>
                <div className="sm:col-span-2">
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Website URL</label>
                  <input type="url" placeholder="https://yourbusiness.com"
                    value={form.website} onChange={e => update('website', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm" />
                </div>
                <div className="sm:col-span-2">
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Full Address *</label>
                  <textarea rows={2} placeholder="Door no., Street, Area, Town"
                    value={form.address} onChange={e => update('address', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm resize-none" />
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">District *</label>
                  <select value={form.district} onChange={e => update('district', e.target.value)}
                    className="search-input w-full px-4 py-3 text-sm">
                    <option value="">Select district</option>
                    {TN_DISTRICTS.map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">State</label>
                  <input type="text" value={form.state} readOnly className="search-input w-full px-4 py-3 text-sm opacity-60" />
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Opening Time</label>
                  <input type="time" value="09:00" className="search-input w-full px-4 py-3 text-sm" />
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Closing Time</label>
                  <input type="time" value="18:00" className="search-input w-full px-4 py-3 text-sm" />
                </div>
              </div>
            </div>
          )}

          {/* STEP 3 — Media Upload */}
          {step === 3 && (
            <div className="space-y-6">
              <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                <Image size={18} className="text-violet-400" /> Media Upload
              </h2>

              {/* Logo Upload */}
              <div>
                <label className="text-xs text-gray-400 font-medium block mb-2">Company Logo</label>
                {form.logoUrl ? (
                  <div className="relative w-32 h-32 rounded-2xl overflow-hidden border border-white/10 group">
                    <img src={form.logoUrl} alt="Logo Preview" className="w-full h-full object-cover" />
                    <button
                      onClick={() => setForm(f => ({ ...f, logoUrl: '' }))}
                      className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <X className="text-rose-400 w-6 h-6" />
                    </button>
                  </div>
                ) : (
                  <label className="flex flex-col items-center justify-center gap-3 p-8 rounded-2xl border-2 border-dashed border-white/15 hover:border-violet-500/50 hover:bg-violet-500/5 transition-all cursor-pointer group">
                    {logoLoading ? (
                      <div className="flex flex-col items-center gap-2">
                        <Loader2 className="animate-spin text-violet-400" size={24} />
                        <span className="text-xs text-gray-400">Uploading {logoProgress}%</span>
                      </div>
                    ) : (
                      <>
                        <div className="text-4xl">🖼️</div>
                        <div className="text-center">
                          <div className="flex items-center gap-2 text-sm font-medium text-white group-hover:text-violet-300 transition-colors">
                            <Upload size={14} /> Click to upload logo
                          </div>
                          <p className="text-xs text-gray-500 mt-1">PNG/JPG, Square, min 200×200px</p>
                        </div>
                      </>
                    )}
                    <input type="file" accept=".png,.jpg,.jpeg" onChange={handleLogoUpload} className="hidden" disabled={logoLoading} />
                  </label>
                )}
              </div>

              {/* Cover Image Upload */}
              <div>
                <label className="text-xs text-gray-400 font-medium block mb-2">Cover Image</label>
                {form.coverUrl ? (
                  <div className="relative w-full h-48 rounded-2xl overflow-hidden border border-white/10 group">
                    <img src={form.coverUrl} alt="Cover Preview" className="w-full h-full object-cover" />
                    <button
                      onClick={() => setForm(f => ({ ...f, coverUrl: '' }))}
                      className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <X className="text-rose-400 w-6 h-6" />
                    </button>
                  </div>
                ) : (
                  <label className="flex flex-col items-center justify-center gap-3 p-8 rounded-2xl border-2 border-dashed border-white/15 hover:border-violet-500/50 hover:bg-violet-500/5 transition-all cursor-pointer group">
                    {coverLoading ? (
                      <div className="flex flex-col items-center gap-2">
                        <Loader2 className="animate-spin text-violet-400" size={24} />
                        <span className="text-xs text-gray-400">Uploading {coverProgress}%</span>
                      </div>
                    ) : (
                      <>
                        <div className="text-4xl">🏞️</div>
                        <div className="text-center">
                          <div className="flex items-center gap-2 text-sm font-medium text-white group-hover:text-violet-300 transition-colors">
                            <Upload size={14} /> Click to upload cover
                          </div>
                          <p className="text-xs text-gray-500 mt-1">JPG/PNG, Landscape 1200×400px recommended</p>
                        </div>
                      </>
                    )}
                    <input type="file" accept=".png,.jpg,.jpeg" onChange={handleCoverUpload} className="hidden" disabled={coverLoading} />
                  </label>
                )}
              </div>

              {/* Gallery Upload */}
              <div>
                <label className="text-xs text-gray-400 font-medium block mb-2">Gallery Images (up to 10)</label>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-3">
                  {form.galleryUrls.map((url, index) => (
                    <div key={index} className="relative aspect-video rounded-xl overflow-hidden border border-white/10 group">
                      <img src={url} alt={`Gallery ${index}`} className="w-full h-full object-cover" />
                      <button
                        onClick={() => setForm(f => ({ ...f, galleryUrls: f.galleryUrls.filter((_, idx) => idx !== index) }))}
                        className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <X className="text-rose-400 w-5 h-5" />
                      </button>
                    </div>
                  ))}
                </div>

                {form.galleryUrls.length < 10 && (
                  <label className="flex flex-col items-center justify-center gap-3 p-8 rounded-2xl border-2 border-dashed border-white/15 hover:border-violet-500/50 hover:bg-violet-500/5 transition-all cursor-pointer group">
                    {galleryLoading ? (
                      <div className="flex flex-col items-center gap-2">
                        <Loader2 className="animate-spin text-violet-400" size={24} />
                        <span className="text-xs text-gray-400">Uploading...</span>
                      </div>
                    ) : (
                      <>
                        <div className="text-4xl">📷</div>
                        <div className="text-center">
                          <div className="flex items-center gap-2 text-sm font-medium text-white group-hover:text-violet-300 transition-colors">
                            <Upload size={14} /> Upload multiple images
                          </div>
                          <p className="text-xs text-gray-500 mt-1">Office, products, team, work site photos</p>
                        </div>
                      </>
                    )}
                    <input type="file" accept=".png,.jpg,.jpeg" multiple onChange={handleGalleryUpload} className="hidden" disabled={galleryLoading} />
                  </label>
                )}
              </div>
            </div>
          )}

          {/* STEP 4 — Details & Social */}
          {step === 4 && (
            <div className="space-y-5">
              <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                <Globe size={18} className="text-violet-400" /> Social Media & Additional Details
              </h2>
              <div className="space-y-4">
                {[
                  { key: 'facebook', label: 'Facebook Page URL', placeholder: 'https://facebook.com/yourpage', icon: '📘' },
                  { key: 'instagram', label: 'Instagram Profile URL', placeholder: 'https://instagram.com/yourhandle', icon: '📷' },
                  { key: 'linkedin', label: 'LinkedIn Company Page', placeholder: 'https://linkedin.com/company/...', icon: '💼' },
                  { key: 'youtube', label: 'YouTube Channel', placeholder: 'https://youtube.com/@yourchannel', icon: '▶️' },
                ].map(({ key, label, placeholder, icon }) => (
                  <div key={key}>
                    <label className="text-xs text-gray-400 font-medium block mb-1.5">{icon} {label}</label>
                    <input type="url" placeholder={placeholder}
                      value={(form as any)[key]} onChange={e => update(key, e.target.value)}
                      className="search-input w-full px-4 py-3 text-sm" />
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 5 — Services */}
          {step === 5 && (
            <div className="space-y-5">
              <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                <FileText size={18} className="text-violet-400" /> Business Services
              </h2>
              <p className="text-sm text-gray-400">Add the services your business offers. These help customers find you and improve SEO.</p>
              <div className="flex gap-2">
                <input type="text" value={newService} onChange={e => setNewService(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && addService()}
                  placeholder="e.g. Tractor Rental, Harvesting Service..."
                  className="search-input flex-1 px-4 py-3 text-sm" />
                <button onClick={addService}
                  className="btn-gradient px-4 py-3 rounded-xl relative z-10 flex items-center gap-1 text-sm font-semibold">
                  <Plus size={15} /> Add
                </button>
              </div>
              {services.length > 0 ? (
                <div className="flex flex-wrap gap-2">
                  {services.map((s, i) => (
                    <span key={i} className="flex items-center gap-2 px-3 py-2 rounded-xl bg-violet-500/10 text-violet-300 border border-violet-500/20 text-sm font-medium">
                      ✓ {s}
                      <button onClick={() => removeService(i)} className="hover:text-rose-400 transition-colors"><X size={13} /></button>
                    </span>
                  ))}
                </div>
              ) : (
                <div className="text-center py-8 text-gray-500 text-sm border border-dashed border-white/10 rounded-2xl">
                  Add at least 3 services to improve discoverability
                </div>
              )}
              <div className="glass-card rounded-2xl p-4 border border-emerald-500/20">
                <p className="text-xs text-emerald-400 font-medium mb-1">💡 SEO Tip</p>
                <p className="text-xs text-gray-400">Each service you add becomes a keyword that helps customers find you on Google. Add specific, detailed service names.</p>
              </div>
            </div>
          )}

          {/* STEP 6 — Preview & Submit */}
          {step === 6 && (
            <div className="space-y-5">
              <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                <Check size={18} className="text-violet-400" /> Preview & Submit
              </h2>

              {/* Preview Card */}
              <div className="glass-card rounded-2xl p-5 border border-violet-500/20">
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-14 h-14 rounded-xl bg-violet-500/10 border border-violet-500/20 flex items-center justify-center text-2xl">🏢</div>
                  <div>
                    <div className="flex items-center gap-2">
                      <h3 className="font-bold text-white">{form.name || 'Your Business Name'}</h3>
                      <span className="badge-verified">PENDING</span>
                    </div>
                    <div className="text-sm text-gray-400">{form.category || 'Category'} • {form.district || 'District'}</div>
                    <div className="text-xs text-violet-400 mt-0.5">
                      thenijobs.com/company/{(form.name || 'your-business').toLowerCase().replace(/\s+/g, '-')}
                    </div>
                  </div>
                </div>
                <p className="text-sm text-gray-400 leading-relaxed">{form.description.slice(0, 200) || 'Your business description will appear here...'}</p>
                {services.length > 0 && (
                  <div className="flex flex-wrap gap-2 mt-3 pt-3 border-t border-white/5">
                    {services.map(s => (
                      <span key={s} className="text-xs px-2.5 py-1 rounded-lg bg-violet-500/10 text-violet-300 border border-violet-500/15">{s}</span>
                    ))}
                  </div>
                )}
              </div>

              {/* What happens next */}
              <div className="space-y-2">
                <p className="text-sm font-semibold text-white">What happens next?</p>
                {[
                  { step: '1', text: 'Your profile will be reviewed within 24 hours', icon: Clock },
                  { step: '2', text: 'Once approved, your SEO page goes live instantly', icon: BadgeCheck },
                  { step: '3', text: 'Google will index your page within 3–7 days', icon: Check },
                ].map(({ step, text, icon: Icon }) => (
                  <div key={step} className="flex items-center gap-3 p-3 rounded-xl bg-white/5">
                    <div className="w-7 h-7 rounded-full bg-violet-600 flex items-center justify-center text-xs font-bold text-white shrink-0">{step}</div>
                    <div className="flex items-center gap-2 text-sm text-gray-300"><Icon size={13} className="text-emerald-400" />{text}</div>
                  </div>
                ))}
              </div>

              <label className="flex items-start gap-3 cursor-pointer">
                <input type="checkbox" className="mt-1 accent-violet-600" />
                <span className="text-xs text-gray-400">
                  I agree to THENIJOBS <Link href="/terms" className="text-violet-400">Terms of Service</Link> and confirm that all information provided is accurate.
                </span>
              </label>
            </div>
          )}

          {/* Navigation Buttons */}
          <div className="flex gap-3 mt-8 pt-6 border-t border-white/5">
            {step > 1 && (
              <button onClick={() => setStep(s => s - 1)}
                className="btn-outline-glass px-5 py-3 rounded-2xl text-sm font-semibold flex items-center gap-2">
                <ArrowLeft size={15} /> Back
              </button>
            )}
            <button
              onClick={step === 6 ? handleSubmit : () => setStep(s => s + 1)}
              disabled={loading}
              className="flex-1 btn-gradient py-3 rounded-2xl font-semibold text-sm relative z-10 flex items-center justify-center gap-2">
              {loading ? <Loader2 size={16} className="animate-spin" /> : null}
              {step === 6 ? 'Submit for Review' : 'Continue'}
              {!loading && <ArrowRight size={15} />}
            </button>
          </div>
        </div>
      </div>
      <BottomNav />
    </main>
  );
}

'use client';

import { useState, useMemo } from 'react';
import {
  Users2, Search, Eye, Download, CheckCircle, XCircle,
  Calendar, Clock, Briefcase,
  Star, X, Mail, Phone, ExternalLink, Loader2, Save, GraduationCap,
  Sparkles
} from 'lucide-react';
import Link from 'next/link';
import { useAuth } from '@/hooks/useAuth';
import { useCollection, useDocument } from '@/hooks/useFirestore';
import { updateApplicationStatus, createDocument, createNotification } from '@/lib/firebase/firestoreService';
import { where, orderBy } from 'firebase/firestore';
import ApplicationPipeline from '@/components/ui/ApplicationPipeline';
import CandidateSuggestionCard from '@/components/ui/CandidateSuggestionCard';

type PipelineStatus = 'all' | 'applied' | 'shortlisted' | 'interview_scheduled' | 'selected' | 'rejected' | 'ai_recommended';

const PIPELINE_TABS: { label: string; value: PipelineStatus; color: string }[] = [
  { label: 'All', value: 'all', color: 'gray' },
  { label: 'New', value: 'applied', color: 'cyan' },
  { label: 'Shortlisted', value: 'shortlisted', color: 'violet' },
  { label: 'Interview', value: 'interview_scheduled', color: 'amber' },
  { label: 'Selected / Hired', value: 'selected', color: 'emerald' },
  { label: 'Rejected', value: 'rejected', color: 'rose' },
  { label: 'AI Recommended 🤖', value: 'ai_recommended', color: 'violet' },
];

const statusConfig: Record<string, { bg: string; text: string; label: string }> = {
  applied: { bg: 'bg-cyan-500/10', text: 'text-cyan-400', label: 'New' },
  shortlisted: { bg: 'bg-violet-500/10', text: 'text-violet-400', label: 'Shortlisted' },
  interview_scheduled: { bg: 'bg-amber-500/10', text: 'text-amber-400', label: 'Interview' },
  selected: { bg: 'bg-emerald-500/10', text: 'text-emerald-400', label: 'Selected' },
  rejected: { bg: 'bg-rose-500/10', text: 'text-rose-400', label: 'Rejected' },
};

function CandidateDetailPanel({
  seekerId,
  applicationId,
  currentStatus,
  initialNotes,
  companyId,
  companyName,
  jobId,
  jobTitle,
  seekerName,
  statusTimestamps,
  onNotesUpdated,
  onUpdateStatus,
  onStatusUpdated
}: {
  seekerId: string;
  applicationId: string;
  currentStatus: string;
  initialNotes?: string;
  companyId: string;
  companyName: string;
  jobId: string;
  jobTitle: string;
  seekerName: string;
  statusTimestamps?: Record<string, any>;
  onNotesUpdated: (notes: string) => void;
  onUpdateStatus: (newStatus: string) => Promise<void>;
  onStatusUpdated: (status: string) => void;
}) {
  const { data: profile, loading: profileLoading } = useDocument<any>('seekerProfiles', seekerId);
  const { data: userDoc, loading: userLoading } = useDocument<any>('users', seekerId);

  const [savingNotes, setSavingNotes] = useState(false);
  const [localNotes, setLocalNotes] = useState(initialNotes || '');

  // Interview Form State
  const [showScheduleForm, setShowScheduleForm] = useState(false);
  const [interviewDate, setInterviewDate] = useState('');
  const [interviewTime, setInterviewTime] = useState('');
  const [interviewMode, setInterviewMode] = useState('Phone');
  const [scheduling, setScheduling] = useState(false);

  const handleSaveNotes = async () => {
    setSavingNotes(true);
    try {
      await updateApplicationStatus(applicationId, currentStatus, localNotes);
      onNotesUpdated(localNotes);
      alert('Notes updated successfully!');
    } catch (err) {
      console.error(err);
      alert('Failed to update notes');
    } finally {
      setSavingNotes(false);
    }
  };

  const handleScheduleInterview = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!interviewDate || !interviewTime) {
      alert('Please fill in both date and time.');
      return;
    }
    setScheduling(true);
    try {
      // Create Interview document
      await createDocument('interviews', {
        companyId,
        companyName,
        seekerId,
        seekerName,
        jobId,
        jobTitle,
        date: interviewDate,
        time: interviewTime,
        mode: interviewMode,
        status: 'scheduled',
      });

      // Update Application status
      await updateApplicationStatus(applicationId, 'interview_scheduled');
      onStatusUpdated('interview_scheduled');

      // Create seeker notification
      await createNotification({
        userId: seekerId,
        type: 'interview',
        title: 'Interview Scheduled! 📅',
        message: `An interview has been scheduled for "${jobTitle}" on ${interviewDate} at ${interviewTime} via ${interviewMode}.`,
        actionUrl: '/seeker/interviews',
      });

      alert('Interview scheduled successfully!');
      setShowScheduleForm(false);
    } catch (err) {
      console.error(err);
      alert('Failed to schedule interview');
    } finally {
      setScheduling(false);
    }
  };

  if (profileLoading || userLoading) {
    return (
      <div className="flex items-center justify-center py-6">
        <Loader2 className="animate-spin text-cyan-400" size={20} />
      </div>
    );
  }

  const email = profile?.email || userDoc?.email || 'N/A';
  const phone = profile?.phone || userDoc?.phone || 'N/A';
  const experienceList = profile?.experience || [];
  const educationList = profile?.education || [];
  const skillsList = profile?.skills || [];
  const district = profile?.district || userDoc?.district || 'Theni';

  // Calculate profile strength
  const strengthItems = [
    { label: 'Photo uploaded', done: !!profile?.photoUrl },
    { label: 'Contact details', done: !!phone && phone !== 'N/A' && !!email && email !== 'N/A' },
    { label: 'Education added', done: educationList.length > 0 },
    { label: 'Experience added', done: experienceList.length > 0 },
    { label: 'Skills added', done: skillsList.length >= 3 },
  ];
  const profileStrength = Math.round((strengthItems.filter(i => i.done).length / strengthItems.length) * 100);

  // Helper to parse Firestore timestamps
  const parseTimestamps = (timestamps?: Record<string, any>): Record<string, Date> | undefined => {
    if (!timestamps) return undefined;
    const parsed: Record<string, Date> = {};
    for (const [key, val] of Object.entries(timestamps)) {
      if (val && typeof val.toDate === 'function') {
        parsed[key] = val.toDate();
      } else if (val && val.seconds) {
        parsed[key] = new Date(val.seconds * 1000);
      } else if (val instanceof Date) {
        parsed[key] = val;
      } else if (typeof val === 'string' || typeof val === 'number') {
        parsed[key] = new Date(val);
      }
    }
    return parsed;
  };

  return (
    <div className="px-5 pb-5 pt-0 border-t border-white/[0.06] animate-fade-in">
      <div className="pt-4 mb-2 overflow-x-auto no-scrollbar">
        <ApplicationPipeline
          currentStatus={currentStatus as any}
          timestamps={parseTimestamps(statusTimestamps)}
          readonly={false}
          onStatusChange={onUpdateStatus}
        />
      </div>
      <div className="pt-2 grid grid-cols-1 md:grid-cols-3 gap-4">
        {/* Contact Info & Notes */}
        <div className="space-y-4">
          <div className="glass-card rounded-xl p-4">
            <h4 className="text-xs font-semibold text-gray-400 mb-3">Contact Info</h4>
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-sm">
                <Phone size={13} className="text-cyan-400" />
                <span className="text-gray-300">{phone}</span>
              </div>
              <div className="flex items-center gap-2 text-sm">
                <Mail size={13} className="text-cyan-400" />
                <span className="text-gray-300 truncate">{email}</span>
              </div>
              {profile?.portfolio && profile.portfolio.length > 0 && (
                <div className="pt-2 border-t border-white/[0.06] space-y-1">
                  <p className="text-[10px] text-gray-500 font-semibold">Links</p>
                  {profile.portfolio.map((link: string, i: number) => (
                    <a key={i} href={link} target="_blank" rel="noreferrer" className="flex items-center gap-1 text-xs text-cyan-400 hover:underline">
                      <ExternalLink size={10} /> {link.replace(/^https?:\/\/(www\.)?/, '')}
                    </a>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Employer Notes */}
          <div className="glass-card rounded-xl p-4">
            <h4 className="text-xs font-semibold text-gray-400 mb-2">Employer Notes</h4>
            <textarea
              className="w-full bg-[#111124] border border-white/10 rounded-lg p-2 text-xs text-white placeholder:text-gray-600 focus:border-cyan-500/40 focus:outline-none resize-none"
              rows={3}
              placeholder="Add review notes, assessment scores, etc..."
              value={localNotes}
              onChange={(e) => setLocalNotes(e.target.value)}
            />
            <button
              onClick={handleSaveNotes}
              disabled={savingNotes}
              className="mt-2 w-full flex items-center justify-center gap-1.5 py-1.5 rounded-lg bg-cyan-600 text-white text-xs font-semibold hover:bg-cyan-500 transition-colors disabled:opacity-50"
            >
              {savingNotes ? <Loader2 size={12} className="animate-spin" /> : <Save size={12} />}
              Save Notes
            </button>
          </div>
        </div>

        {/* Education & Experience */}
        <div className="glass-card rounded-xl p-4 space-y-4">
          <div>
            <h4 className="text-xs font-semibold text-gray-400 mb-2 flex items-center gap-1.5">
              <Briefcase size={12} className="text-violet-400" /> Experience
            </h4>
            {experienceList.length === 0 ? (
              <p className="text-xs text-gray-500 italic">No experience documented</p>
            ) : (
              <div className="space-y-3">
                {experienceList.map((exp: any, i: number) => (
                  <div key={i} className="text-xs border-l-2 border-violet-500/20 pl-2">
                    <p className="font-semibold text-white">{exp.role}</p>
                    <p className="text-gray-400">{exp.company} ({exp.startDate} - {exp.endDate})</p>
                    {exp.description && <p className="text-gray-500 text-[10px] mt-1">{exp.description}</p>}
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="pt-3 border-t border-white/[0.06]">
            <h4 className="text-xs font-semibold text-gray-400 mb-2 flex items-center gap-1.5">
              <GraduationCap size={12} className="text-emerald-400" /> Education
            </h4>
            {educationList.length === 0 ? (
              <p className="text-xs text-gray-500 italic">No education documented</p>
            ) : (
              <div className="space-y-3">
                {educationList.map((edu: any, i: number) => (
                  <div key={i} className="text-xs border-l-2 border-emerald-500/20 pl-2">
                    <p className="font-semibold text-white">{edu.degree} {edu.field && `in ${edu.field}`}</p>
                    <p className="text-gray-400">{edu.institution} ({edu.year})</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Profile Strength & Schedule Interview */}
        <div className="space-y-4">
          <div className="glass-card rounded-xl p-4">
            <h4 className="text-xs font-semibold text-gray-400 mb-3">Profile Strength</h4>
            <div className="flex items-center gap-3 mb-2">
              <div className="flex-1 h-2 bg-white/5 rounded-full overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-cyan-500 to-emerald-500 rounded-full"
                  style={{ width: `${profileStrength}%` }}
                />
              </div>
              <span className="text-xs font-bold text-cyan-400">{profileStrength}%</span>
            </div>
            <div className="flex flex-wrap gap-1 mt-2">
              {skillsList.map((s: string) => (
                <span key={s} className="px-1.5 py-0.5 rounded bg-white/[0.04] text-[9px] text-gray-400 border border-white/[0.06]">
                  {s}
                </span>
              ))}
            </div>
          </div>

          {/* Schedule Interview section */}
          {currentStatus !== 'rejected' && currentStatus !== 'selected' && (
            <div className="glass-card rounded-xl p-4">
              {!showScheduleForm ? (
                <button
                  onClick={() => setShowScheduleForm(true)}
                  className="w-full flex items-center justify-center gap-2 py-2 rounded-lg bg-amber-500/10 border border-amber-500/25 hover:bg-amber-500/20 text-amber-400 text-xs font-bold transition-all"
                >
                  <Calendar size={14} />
                  Schedule Interview
                </button>
              ) : (
                <form onSubmit={handleScheduleInterview} className="space-y-3">
                  <div className="flex items-center justify-between border-b border-white/[0.06] pb-2 mb-2">
                    <span className="text-xs font-semibold text-amber-400">Schedule Interview</span>
