    if (jobFilter !== 'All Jobs') {
      targetJob = companyJobs.find((j: any) => j.title === jobFilter) || companyJobs[0];
    }

    return seekerProfiles
      .map((seeker: any) => {
        const match = calculateMatch(targetJob, seeker);
        if (match) {
          return {
            ...match,
            inviteStatus: sentInvites[seeker.id] ? 'sent' : 'none'
