type JobStatus = 'active' | 'paused' | 'draft' | 'closed' | 'expired';
type TabFilter = 'all' | JobStatus;

interface JobDoc {
  id: string;
  title: string;
  jobType: string;
  location?: string;
  district?: string;
  salaryMin?: number;
  salaryMax?: number;
  salary?: string; // fallback
  applicationsCount?: number;
  viewCount?: number;
  status?: JobStatus;
  isActive?: boolean;
  isFeatured?: boolean;
  isPremium?: boolean;
  isUrgent?: boolean;
  createdAt?: any;
  deadline?: any;
}

const TABS: { label: string; value: TabFilter }[] = [
  { label: 'All', value: 'all' },
  { label: 'Active', value: 'active' },
  { label: 'Paused', value: 'paused' },
  { label: 'Draft', value: 'draft' },
  { label: 'Closed', value: 'closed' },
  { label: 'Expired', value: 'expired' },
];

const statusConfig: Record<JobStatus, { bg: string; text: string; label: string }> = {
  active: { bg: 'bg-emerald-500/10', text: 'text-emerald-400', label: 'Active' },
  paused: { bg: 'bg-amber-500/10', text: 'text-amber-400', label: 'Paused' },
  draft: { bg: 'bg-gray-500/10', text: 'text-gray-400', label: 'Draft' },
  closed: { bg: 'bg-rose-500/10', text: 'text-rose-400', label: 'Closed' },
  expired: { bg: 'bg-gray-500/10', text: 'text-gray-500', label: 'Expired' },
};

const INITIAL_COLORS = [
  'from-violet-500 to-indigo-500',
  'from-cyan-500 to-blue-500',
  'from-emerald-500 to-teal-500',
  'from-amber-500 to-orange-500',
  'from-rose-500 to-pink-500',
  'from-purple-500 to-violet-500',
  'from-blue-500 to-cyan-500',
  'from-teal-500 to-emerald-500',
];

export default function EmployerJobsPage() {
  const { user } = useAuth();

  // 1. Fetch employer's company
  const { data: companies, loading: companyLoading } = useCollection<any>('companies', [
    where('ownerId', '==', user?.uid || '')
  ], { skip: !user?.uid });

  const company = companies[0];
  const companyId = company?.id;

  // 2. Fetch jobs
  const { data: jobs, loading: jobsLoading } = useCollection<JobDoc>('jobs', [
    where('companyId', '==', companyId || ''),
    orderBy('createdAt', 'desc')
  ], { skip: !companyId });

  const [tab, setTab] = useState<TabFilter>('all');
  const [search, setSearch] = useState('');
  const [openMenuId, setOpenMenuId] = useState<string | null>(null);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const filtered = jobs.filter((j) => {
    const isJobActive = j.isActive !== false && j.status !== 'paused' && j.status !== 'closed' && j.status !== 'expired';
    const jobStatus = j.status || (isJobActive ? 'active' : 'draft');

    if (tab !== 'all' && jobStatus !== tab) return false;
    if (search && !j.title.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const handleToggleStatus = async (id: string, currentStatus?: JobStatus) => {
    setActionLoading(id);
    try {
      const nextStatus: JobStatus = currentStatus === 'active' || !currentStatus ? 'paused' : 'active';
      const isActive = nextStatus === 'active';
      await updateDocument('jobs', id, { status: nextStatus, isActive });
    } catch (err) {
      console.error('Toggle status error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleCloseJob = async (id: string) => {
    setActionLoading(id);
    try {
      await updateDocument('jobs', id, { status: 'closed', isActive: false });
    } catch (err) {
      console.error('Close job error:', err);
    } finally {
      setActionLoading(null);
      setOpenMenuId(null);
    }
  };

  const handleDeleteJob = async (id: string) => {
    if (!window.confirm('Are you sure you want to delete this job posting permanently?')) return;
    setActionLoading(id);
    try {
      await deleteDocument('jobs', id);
    } catch (err) {
      console.error('Delete job error:', err);
    } finally {
      setActionLoading(null);
      setOpenMenuId(null);
    }
  };

  const handleUpgradePremium = async (id: string) => {
    setActionLoading(id);
    try {
      await updateDocument('jobs', id, { isPremium: true });
    } catch (err) {
      console.error('Premium upgrade error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  // Dynamic statistics
  const activeCount = jobs.filter((j) => (j.status === 'active' || (!j.status && j.isActive !== false))).length;
  const pausedCount = jobs.filter((j) => j.status === 'paused').length;
  const closedCount = jobs.filter((j) => j.status === 'closed').length;
  const totalAppsCount = jobs.reduce((sum, j) => sum + (j.applicationsCount || 0), 0);

  const stats = [
    { label: 'Active Jobs', count: activeCount, icon: Briefcase, color: 'cyan' },
    { label: 'Paused', count: pausedCount, icon: Pause, color: 'amber' },
    { label: 'Closed', count: closedCount, icon: X, color: 'rose' },
    { label: 'Total Applications', count: totalAppsCount, icon: Users2, color: 'violet' },
  ];

  const colorMap: Record<string, { bg: string; text: string }> = {
    cyan: { bg: 'bg-cyan-500/10', text: 'text-cyan-400' },
    amber: { bg: 'bg-amber-500/10', text: 'text-amber-400' },
    rose: { bg: 'bg-rose-500/10', text: 'text-rose-400' },
    violet: { bg: 'bg-violet-500/10', text: 'text-violet-400' },
  };

  const loading = companyLoading || jobsLoading;

  if (!companyId && !companyLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-center font-outfit">
        <Briefcase size={48} className="text-gray-600 mb-4" />
        <h2 className="text-lg font-semibold text-white">No Company Profile</h2>
        <p className="text-sm text-gray-400 mt-2 max-w-sm">Please register your company profile first to post and manage jobs.</p>
        <Link href="/employer/company-profile" className="mt-4 px-5 py-2.5 rounded-xl bg-gradient-to-r from-cyan-600 to-emerald-600 text-white font-semibold hover:opacity-90">
          Setup Company Profile
        </Link>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in-up font-outfit">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white font-outfit">Job Management</h1>
          <p className="text-sm text-gray-400 mt-1">Manage and monitor all your job listings</p>
        </div>
        <Link
          href="/employer/post-job"
          className="inline-flex items-center gap-2 px-5 py-2.5 rounded-xl bg-gradient-to-r from-cyan-600 to-emerald-600 text-white text-sm font-semibold hover:opacity-90 transition-opacity"
        >
          <Plus size={16} />
          Post New Job
        </Link>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20">
          <Loader2 size={36} className="text-cyan-400 animate-spin mb-4" />
          <p className="text-sm text-gray-400">Loading jobs...</p>
        </div>
      ) : (
        <>
          {/* Stats Cards */}
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            {stats.map((stat) => {
              const colors = colorMap[stat.color];
              const Icon = stat.icon;
              return (
                <div key={stat.label} className="glass-card rounded-2xl p-4 hover:border-white/15 transition-all">
                  <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-xl ${colors.bg} flex items-center justify-center`}>
                      <Icon size={18} className={colors.text} />
                    </div>
                    <div>
                      <p className="text-xl font-bold text-white">{stat.count}</p>
                      <p className="text-[11px] text-gray-500">{stat.label}</p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Tab Filters */}
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex items-center gap-1 overflow-x-auto no-scrollbar bg-white/[0.03] rounded-xl p-1 border border-white/[0.06] flex-1">
              {TABS.map((t) => {
                const count = t.value === 'all' ? jobs.length : jobs.filter((j) => {
                  const isJobActive = j.isActive !== false && j.status !== 'paused' && j.status !== 'closed' && j.status !== 'expired';
                  const jobStatus = j.status || (isJobActive ? 'active' : 'draft');
                  return jobStatus === t.value;
                }).length;

                return (
                  <button
                    key={t.value}
                    onClick={() => setTab(t.value)}
                    className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all ${
                      tab === t.value
                        ? 'bg-cyan-500/15 text-cyan-300 border border-cyan-500/20'
                        : 'text-gray-400 hover:text-white hover:bg-white/[0.04]'
                    }`}
                  >
                    {t.label} <span className="text-[10px] opacity-70">({count})</span>
                  </button>
                );
              })}
            </div>
            <div className="relative max-w-sm">
              <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
              <input
                type="text"
                placeholder="Search jobs..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-white placeholder:text-gray-600 focus:border-cyan-500/40 outline-none transition-all"
              />
            </div>
          </div>

          {/* Job Cards */}
          <div className="space-y-3">
            {filtered.length === 0 ? (
              <div className="glass-card rounded-2xl p-12 text-center">
                <Briefcase size={32} className="text-gray-600 mx-auto mb-3" />
                <p className="text-sm text-gray-400">No jobs found matching your selection.</p>
              </div>
            ) : (
              filtered.map((job) => {
                const isJobActive = job.isActive !== false && job.status !== 'paused' && job.status !== 'closed' && job.status !== 'expired';
                const jobStatus = job.status || (isJobActive ? 'active' : 'draft');
                const status = statusConfig[jobStatus] || statusConfig.draft;
                const salaryText = job.salaryMin && job.salaryMax ? `₹${job.salaryMin.toLocaleString('en-IN')} - ₹${job.salaryMax.toLocaleString('en-IN')}/mo` : job.salary || 'Salary N/A';

                return (
                  <div
                    key={job.id}
                    className="glass-card rounded-2xl p-5 hover:border-white/15 transition-all"
                  >
                    <div className="flex flex-col lg:flex-row lg:items-center gap-4">
                      {/* Job Info */}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap mb-1">
                          <h3 className="text-sm font-semibold text-white">{job.title}</h3>
                          <span className="px-2 py-0.5 rounded-lg text-[10px] font-semibold bg-cyan-500/10 text-cyan-400 uppercase">
                            {job.jobType || 'Full Time'}
                          </span>
                          {job.isUrgent && (
                            <span className="px-2 py-0.5 rounded-lg text-[10px] font-bold bg-amber-500/10 text-amber-400 flex items-center gap-0.5">
                              URGENT
                            </span>
                          )}
                          {job.isPremium && (
                            <span className="px-2 py-0.5 rounded-lg text-[10px] font-bold bg-violet-500/10 text-violet-400">
                              PREMIUM
                            </span>
                          )}
                          <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${status.bg} ${status.text}`}>
                            {status.label}
                          </span>
                        </div>
                        <p className="text-xs text-gray-500">
                          {job.district || 'Theni'} · {job.location || 'Local'} · {salaryText} · Posted {job.createdAt ? new Date(job.createdAt).toLocaleDateString() : 'Recently'}
                        </p>
                      </div>

                      {/* Stats */}
                      <div className="flex items-center gap-6 lg:gap-8">
                        <div className="text-center">
                          <div className="flex items-center justify-center gap-1 text-sm font-bold text-white">
                            <Users2 size={14} className="text-cyan-400" />
                            {job.applicationsCount || 0}
                          </div>
                          <p className="text-[10px] text-gray-500">Applications</p>
                        </div>
                        <div className="text-center">
                          <div className="flex items-center justify-center gap-1 text-sm font-bold text-white">
                            <Eye size={14} className="text-violet-400" />
                            {job.viewCount || 0}
                          </div>
                          <p className="text-[10px] text-gray-500">Views</p>
                        </div>
                      </div>

                      {/* Actions */}
                      <div className="flex items-center gap-2">
                        {actionLoading === job.id ? (
                          <Loader2 size={16} className="text-cyan-400 animate-spin" />
                        ) : (
                          <>
                            {(jobStatus === 'active' || jobStatus === 'paused') && (
                              <button
                                onClick={() => handleToggleStatus(job.id, jobStatus)}
                                className={`p-2 rounded-lg transition-all ${
                                  jobStatus === 'active'
                                    ? 'bg-amber-500/10 text-amber-400 hover:bg-amber-500/20'
                                    : 'bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20'
                                }`}
                                title={jobStatus === 'active' ? 'Pause Posting' : 'Resume Posting'}
                              >
                                {jobStatus === 'active' ? <Pause size={14} /> : <Play size={14} />}
                              </button>
                            )}
                            {!job.isPremium && jobStatus === 'active' && (
                              <button
                                onClick={() => handleUpgradePremium(job.id)}
                                className="p-2 rounded-lg bg-violet-500/10 text-violet-400 hover:bg-violet-500/20 transition-all"
                                title="Premium Upgrade"
                              >
                                <Zap size={14} />
                              </button>
                            )}
                            <div className="relative">
                              <button
                                onClick={() => setOpenMenuId(openMenuId === job.id ? null : job.id)}
                                className="p-2 rounded-lg bg-white/[0.04] text-gray-400 hover:bg-white/[0.08] transition-all"
                              >
                                <MoreVertical size={14} />
                              </button>
                              {openMenuId === job.id && (
                                <div className="absolute right-0 top-10 w-40 bg-[#141428] border border-white/10 rounded-xl shadow-xl z-20 overflow-hidden">
                                  {jobStatus !== 'closed' && (
                                    <button
                                      onClick={() => handleCloseJob(job.id)}
                                      className="w-full flex items-center gap-2 px-4 py-2.5 text-sm text-gray-300 hover:bg-white/[0.04] transition-colors"
                                    >
                                      <X size={14} /> Close Job
                                    </button>
                                  )}
                                  <button
                                    onClick={() => handleDeleteJob(job.id)}
                                    className="w-full flex items-center gap-2 px-4 py-2.5 text-sm text-rose-400 hover:bg-rose-500/10 transition-colors"
                                  >
                                    <Trash2 size={14} /> Delete
                                  </button>
                                </div>
                              )}
                            </div>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import Header from '@/components/navigation/Header';
import BottomNav from '@/components/navigation/BottomNav';
import {
  MapPin, Briefcase, Banknote, Clock, Users, BadgeCheck, BookmarkPlus, Share2, Zap, Building2, ChevronRight,
  CheckCircle, BellRing, MessageCircle, Loader2, FileText
} from 'lucide-react';
import { useAuth } from '@/hooks/useAuth';
import { useDocument } from '@/hooks/useFirestore';
import { db } from '@/lib/firebase/config';
import { doc, getDoc, addDoc, collection, query, where, getDocs, writeBatch, serverTimestamp } from 'firebase/firestore';

interface JobRecord {
  id: string;
  title: string;
  companyName: string;
  companyId: string;
  location: string;
  district: string;
  state: string;
  salaryMin: number;
  salaryMax: number;
  jobType: string;
  posted: string;
  openings: number;
  logo: string;
  isUrgent: boolean;
  isVerified: boolean;
  whatsapp?: string;
  phone?: string;
  experience?: string;
  education?: string;
  deadline?: string;
  description: string;
  responsibilities?: string[];
  requirements?: string[];
  skills?: string[];
  benefits?: string[];
}

export default function JobDetailPageClient({ id }: { id: string }) {
  const router = useRouter();
  const { user } = useAuth();
  const uid = user?.uid;

  const [job, setJob] = useState<JobRecord | null>(null);
  const [loading, setLoading] = useState(true);
  const [saved, setSaved] = useState(false);
  const [applying, setApplying] = useState(false);
  const [hasApplied, setHasApplied] = useState(false);
  const [showApplyModal, setShowApplyModal] = useState(false);
  const [coverLetter, setCoverLetter] = useState('');
  const [selectedResumeId, setSelectedResumeId] = useState('');

  // Fetch seekerProfile to check their resumes
  const { data: seekerProfile } = useDocument<any>('seekerProfiles', uid);
  const resumes = seekerProfile?.resumes || [];

  // 1. Fetch job details from Firestore
  useEffect(() => {
    if (!id) return;
    async function loadJob() {
      try {
        setLoading(true);
        const docSnap = await getDoc(doc(db, 'jobs', id));
        if (docSnap.exists()) {
          const d = docSnap.data();
          setJob({
            id: docSnap.id,
            title: d.title || '',
            companyName: d.companyName || 'Verified Employer',
            companyId: d.companyId || '',
            location: d.location || d.district || 'Theni',
            district: d.district || 'Theni',
            state: d.state || 'Tamil Nadu',
            salaryMin: d.salaryMin || 0,
            salaryMax: d.salaryMax || 0,
            jobType: d.jobType || 'full_time',
            posted: d.createdAt ? new Date(d.createdAt.seconds * 1000).toLocaleDateString('en-IN') : 'Recently',
            openings: d.openings ? Number(d.openings) : 1,
            logo: d.logo || '',
            isUrgent: d.isUrgent || false,
            isVerified: d.isVerified || false,
            whatsapp: d.whatsapp || d.phone || '919876543210',
            phone: d.phone || '',
            experience: d.experience || 'Not specified',
            education: d.education || 'Not specified',
            deadline: d.expiresAt ? new Date(d.expiresAt.seconds * 1000).toLocaleDateString('en-IN') : 'N/A',
            description: d.description || '',
            responsibilities: d.responsibilities || [],
            requirements: d.requirements || [],
            skills: d.skills || [],
            benefits: d.benefits || []
          });
        }
      } catch (err) {
        console.error('Error loading job details:', err);
      } finally {
        setLoading(false);
      }
    }
    loadJob();
  }, [id]);

  // 2. Check if job is saved & if already applied
  useEffect(() => {
    if (!uid || !id) return;
    async function checkSavedAndApplied() {
      try {
        // Check saved
        const qSaved = query(collection(db, 'savedJobs'), where('userId', '==', uid), where('jobId', '==', id));
        const snapSaved = await getDocs(qSaved);
        setSaved(!snapSaved.empty);

        // Check applied
        const qApplied = query(collection(db, 'applications'), where('seekerId', '==', uid), where('jobId', '==', id));
        const snapApplied = await getDocs(qApplied);
        setHasApplied(!snapApplied.empty);
      } catch (err) {
        console.error(err);
      }
    }
    checkSavedAndApplied();
  }, [uid, id]);

  // Set default resume selection
  useEffect(() => {
    if (resumes.length > 0) {
      const def = resumes.find((r: any) => r.isDefault);
      setSelectedResumeId(def ? def.id : resumes[0].id);
    }
  }, [resumes]);

  const handleToggleSave = async () => {
    if (!uid || !job) {
      alert('Please login to save this job.');
      return;
    }
    try {
      if (saved) {
        const q = query(collection(db, 'savedJobs'), where('userId', '==', uid), where('jobId', '==', id));
        const snap = await getDocs(q);
        const batch = writeBatch(db);
        snap.docs.forEach(doc => batch.delete(doc.ref));
        await batch.commit();
        setSaved(false);
      } else {
        await addDoc(collection(db, 'savedJobs'), {
          userId: uid,
          jobId: job.id,
          jobTitle: job.title,
          companyName: job.companyName,
          description: job.description,
          district: job.location,
          jobType: job.jobType,
          salaryMin: job.salaryMin,
          salaryMax: job.salaryMax,
          savedAt: serverTimestamp()
        });
        setSaved(true);
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleApply = async () => {
    if (!uid || !job) {
      alert('Please login as a seeker to apply.');
      router.push('/login');
      return;
    }

    setApplying(true);
    try {
      const selectedResume = resumes.find((r: any) => r.id === selectedResumeId);

      await addDoc(collection(db, 'applications'), {
        jobId: job.id,
        jobTitle: job.title,
        companyId: job.companyId,
        companyName: job.companyName,
        seekerId: uid,
        seekerName: seekerProfile?.name || user?.displayName || 'Job Seeker',
        seekerEmail: user?.email || '',
        seekerPhone: seekerProfile?.phone || '',
        resumeURL: selectedResume?.url || '',
        resumeName: selectedResume?.name || 'Profile Apply',
        coverLetter: coverLetter.trim(),
        status: 'applied',
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp()
      });

      // Update applicationCount on job
      // Note: we can just do a merge update or skip for simplicity of direct writes
      setHasApplied(true);
      setShowApplyModal(false);
      alert('Application submitted successfully!');
    } catch (err) {
      console.error(err);
      alert('Failed to submit application.');
    } finally {
      setApplying(false);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-[#0a0a1a] text-white">
        <Loader2 size={36} className="text-emerald-400 animate-spin mb-4" />
        <p className="text-sm text-gray-400">Loading job details...</p>
      </div>
    );
  }

  if (!job) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-[#0a0a1a] text-white p-6 text-center">
        <h2 className="text-lg font-bold">Job Not Found</h2>
        <p className="text-gray-400 text-sm mt-1">This job posting may have expired or been deleted.</p>
        <Link href="/jobs" className="mt-4 px-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-xs font-semibold text-gray-300">
          Back to Jobs List
        </Link>
      </div>
    );
  }

  const salaryStr = job.salaryMin && job.salaryMax
    ? `₹${job.salaryMin.toLocaleString('en-IN')} - ₹${job.salaryMax.toLocaleString('en-IN')}`
    : 'Salary Negotiable';

  return (
    <main className="min-h-screen bg-[#0a0a1a] font-outfit text-white">
      <Header />
      <div className="max-w-5xl mx-auto px-4 sm:px-6 pt-20 pb-28 md:pb-12">
        {/* Breadcrumb */}
        <nav className="flex items-center gap-1.5 text-xs text-gray-500 mt-4 mb-6">
          <Link href="/" className="hover:text-white transition-colors">Home</Link>
          <ChevronRight size={11} />
          <Link href="/jobs" className="hover:text-white transition-colors">Jobs</Link>
          <ChevronRight size={11} />
          <span className="text-white truncate max-w-[200px]">{job.title}</span>
        </nav>

        <div className="grid lg:grid-cols-3 gap-6">
          {/* Main Column */}
          <div className="lg:col-span-2 space-y-5">
            {/* Header Card */}
            <div className="glass-card rounded-2xl p-6">
              <div className="flex gap-4">
                <div className="w-16 h-16 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center text-3xl font-bold shrink-0">
                  {job.logo || (job.companyName ? job.companyName.substring(0, 2).toUpperCase() : '💼')}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-2 flex-wrap">
                    <div>
                      <div className="flex items-center gap-2 flex-wrap mb-1">
                        <h1 className="text-xl font-bold text-white leading-tight">{job.title}</h1>
                        {job.isUrgent && (
                          <span className="flex items-center gap-1 text-[10px] font-bold text-amber-400 bg-amber-400/10 px-2 py-0.5 rounded-full border border-amber-400/20">
                            <Zap size={9} className="fill-current" /> URGENT
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-1.5 text-violet-400 hover:text-violet-300 transition-colors font-medium text-sm">
                        <Building2 size={14} /> {job.companyName}
                        {job.isVerified && <BadgeCheck size={13} className="text-emerald-400" />}
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button
                        onClick={handleToggleSave}
                        className={`p-2.5 rounded-xl border transition-all ${
                          saved ? 'bg-violet-500/20 border-violet-500/40 text-violet-400' : 'btn-outline-glass text-gray-400 hover:text-violet-400'
                        }`}
                      >
                        <BookmarkPlus size={16} className={saved ? 'fill-current' : ''} />
                      </button>
                      <button className="p-2.5 rounded-xl btn-outline-glass text-gray-400 hover:text-white transition-all">
                        <Share2 size={16} />
                      </button>
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-x-4 gap-y-1.5 mt-3 text-sm text-gray-450">
                    <span className="flex items-center gap-1.5"><MapPin size={13} className="text-violet-400" />{job.location}, {job.state}</span>
                    <span className="flex items-center gap-1.5"><Banknote size={13} className="text-emerald-400" />{salaryStr} / Month</span>
                    <span className="flex items-center gap-1.5"><Briefcase size={13} className="text-cyan-400" />{job.jobType.replace('_', ' ').toUpperCase()}</span>
                    <span className="flex items-center gap-1.5"><Users size={13} />{job.openings} Opening{job.openings > 1 ? 's' : ''}</span>
                    <span className="flex items-center gap-1.5"><Clock size={13} />Posted {job.posted}</span>
                  </div>
                </div>
              </div>

              {/* Application CTA Row */}
              <div className="flex gap-3 mt-5 pt-5 border-t border-white/5">
                {hasApplied ? (
                  <button disabled className="flex-1 py-3.5 rounded-xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 font-semibold text-sm cursor-not-allowed">
                    Applied ✓
                  </button>
                ) : (
                  <button
                    onClick={() => setShowApplyModal(true)}
                    className="flex-1 btn-gradient py-3.5 rounded-xl font-semibold text-sm relative z-10 flex items-center justify-center gap-2"
                  >
                    Apply Now
                  </button>
                )}
                {job.whatsapp && (
                  <a
                    href={`https://wa.me/${job.whatsapp}?text=Hi, I am interested in the ${job.title} position at ${job.companyName}`}
                    target="_blank" rel="noopener noreferrer"
                    className="px-5 py-3.5 rounded-xl font-semibold text-sm text-white flex items-center justify-center gap-2"
                    style={{ background: 'linear-gradient(135deg, #25D366, #128C7E)' }}
                  >
                    <MessageCircle size={15} /> WhatsApp Apply
                  </a>
                )}
              </div>
            </div>

            {/* Quick specifications */}
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              {[
                { label: 'Experience', value: job.experience, icon: '💼' },
                { label: 'Education', value: job.education, icon: '🎓' },
                { label: 'Openings', value: `${job.openings} post${job.openings > 1 ? 's' : ''}`, icon: '👥' },
                { label: 'Deadline', value: job.deadline, icon: '📅' },
              ].map(({ label, value, icon }) => (
                <div key={label} className="glass-card rounded-2xl p-4 text-center">
                  <div className="text-xl mb-1">{icon}</div>
                  <div className="text-xs text-gray-500 mb-0.5">{label}</div>
                  <div className="text-sm font-semibold text-white truncate">{value}</div>
                </div>
              ))}
            </div>

            {/* Job Description */}
            <div className="glass-card rounded-2xl p-6">
              <h2 className="text-base font-semibold text-white mb-3">Job Description</h2>
              <p className="text-gray-300 text-sm leading-relaxed whitespace-pre-line">{job.description}</p>
            </div>

            {/* Responsibilities */}
            {job.responsibilities && job.responsibilities.length > 0 && (
              <div className="glass-card rounded-2xl p-6">
                <h2 className="text-base font-semibold text-white mb-4">Key Responsibilities</h2>
                <ul className="space-y-2.5">
                  {job.responsibilities.map((r: string) => (
                    <li key={r} className="flex items-start gap-3 text-sm text-gray-300">
                      <CheckCircle size={15} className="text-emerald-400 mt-0.5 shrink-0" />
                      {r}
                    </li>
                  ))}
                </ul>
              </div>
            )}

            {/* Requirements */}
            {job.requirements && job.requirements.length > 0 && (
              <div className="glass-card rounded-2xl p-6">
                <h2 className="text-base font-semibold text-white mb-4">Requirements</h2>
                <ul className="space-y-2.5">
                  {job.requirements.map((r: string) => (
                    <li key={r} className="flex items-start gap-3 text-sm text-gray-300">
                      <span className="text-violet-400 mt-0.5 shrink-0">▸</span>
                      {r}
                    </li>
                  ))}
                </ul>
              </div>
            )}

            {/* Required Skills */}
            {job.skills && job.skills.length > 0 && (
              <div className="glass-card rounded-2xl p-6">
                <h2 className="text-base font-semibold text-white mb-4">Required Skills</h2>
                <div className="flex flex-wrap gap-2">
                  {job.skills.map((skill: string) => (
                    <span key={skill} className="px-3 py-1.5 rounded-xl bg-violet-500/10 text-violet-300 text-sm border border-violet-500/20 font-medium">
                      {skill}
                    </span>
                  ))}
                </div>
              </div>
            )}

            {/* Benefits */}
            {job.benefits && job.benefits.length > 0 && (
              <div className="glass-card rounded-2xl p-6">
                <h2 className="text-base font-semibold text-white mb-4">Benefits & Perks</h2>
                <div className="flex flex-wrap gap-2">
                  {job.benefits.map((b: string) => (
                    <span key={b} className="px-3 py-1.5 rounded-xl bg-emerald-500/10 text-emerald-300 text-sm border border-emerald-500/20 font-medium flex items-center gap-1.5">
                      ✓ {b}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Right Sidebar */}
          <div className="space-y-4">
            <div className="glass-card rounded-2xl p-5 sticky top-20">
              <div className="text-center mb-4">
                <div className="text-2xl font-bold text-white">{salaryStr}</div>
                <div className="text-xs text-gray-500">per month</div>
              </div>
              {hasApplied ? (
                <button disabled className="w-full py-3.5 rounded-xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 font-semibold text-sm cursor-not-allowed mb-3">
                  Applied ✓
                </button>
              ) : (
                <button onClick={() => setShowApplyModal(true)} className="w-full btn-gradient py-3.5 rounded-xl font-semibold text-sm relative z-10 mb-3">
                  Apply Now
                </button>
              )}
              {job.phone && (
                <a
                  href={`tel:${job.phone}`}
                  className="w-full btn-outline-glass py-3 rounded-xl text-sm font-medium flex items-center justify-center gap-2 mb-2"
                >
                  📞 Call HR
                </a>
              )}
              <p className="text-center text-[10px] text-gray-655 mt-2">
                🔒 Your details are kept private and secure
              </p>
            </div>

            <div className="glass-card rounded-2xl p-5 border border-cyan-500/15">
              <div className="flex items-start gap-3">
                <div className="w-10 h-10 rounded-xl bg-cyan-500/10 flex items-center justify-center flex-shrink-0">
                  <BellRing size={18} className="text-cyan-300" />
                </div>
                <div className="space-y-2">
                  <h3 className="text-sm font-bold text-white">Job Alerts</h3>
                  <p className="text-xs text-gray-400 leading-relaxed">
                    {job.location} பகுதியில் இதுபோன்ற jobs வந்தவுடன் mobile alert பெறலாம்.
                  </p>
                  <Link
                    href="/seeker/job-alerts"
                    className="inline-flex items-center gap-1.5 text-xs font-semibold text-cyan-300 hover:text-cyan-200"
                  >
                    Create Job Alert <ChevronRight size={13} />
                  </Link>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      <BottomNav />

      {/* Apply Modal */}
      {showApplyModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="glass-card rounded-2xl w-full max-w-lg overflow-hidden border border-emerald-500/20 shadow-2xl relative p-6 space-y-4">
            <h3 className="text-lg font-bold text-white">Apply for {job.title}</h3>

            {resumes.length === 0 ? (
              <div className="text-center py-6 border border-dashed border-white/10 rounded-xl space-y-3 p-4">
                <FileText className="mx-auto text-gray-500" size={30} />
                <p className="text-xs text-gray-400">You need to upload or build a resume in your Seeker Portal first before applying.</p>
                <Link
                  href="/seeker/resume"
                  className="inline-block px-4 py-2 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-xs font-semibold text-white"
                >
                  Manage Resumes
                </Link>
              </div>
            ) : (
              <div className="space-y-4">
                <div>
                  <label className="text-xs text-gray-400 block mb-1.5 font-medium">Select Resume</label>
                  <select
                    value={selectedResumeId}
                    onChange={e => setSelectedResumeId(e.target.value)}
                    className="search-input w-full px-3 py-2.5 text-sm bg-[#0a0a1a]"
                  >
                    {resumes.map((r: any) => (
                      <option key={r.id} value={r.id}>
                        {r.name} ({r.uploadDate})
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="text-xs text-gray-400 block mb-1.5 font-medium">Cover Letter / Message to Recruiter</label>
                  <textarea
                    rows={4}
                    value={coverLetter}
                    onChange={e => setCoverLetter(e.target.value)}
                    placeholder="Briefly state why you're a good fit for this role..."
                    className="search-input w-full px-3 py-2.5 text-sm bg-[#0a0a1a] resize-none"
                  />
                </div>

                <div className="flex gap-3 pt-2">
                  <button
                    onClick={() => setShowApplyModal(false)}
                    className="flex-1 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-xs font-semibold hover:bg-white/[0.08]"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={handleApply}
                    disabled={applying}
                    className="flex-1 py-3 rounded-xl bg-gradient-to-r from-emerald-600 to-cyan-600 text-white font-semibold text-xs hover:opacity-90 flex items-center justify-center gap-1.5 disabled:opacity-50"
                  >
                    {applying && <Loader2 size={12} className="animate-spin" />}
                    Submit Application
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </main>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import Header from '@/components/navigation/Header';
import BottomNav from '@/components/navigation/BottomNav';
import {
  Search, MapPin, X, Briefcase, Clock, Banknote,
  Zap, Star, BookmarkPlus, SlidersHorizontal,
  Building2, ArrowRight, BadgeCheck, Loader2
} from 'lucide-react';

import { collection, getDocs, query, where, addDoc, writeBatch, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase/config';
import { useEffect } from 'react';
import { useAuth } from '@/hooks/useAuth';

const JOB_TYPES = ['Full Time', 'Part Time', 'Remote', 'WFH', 'Internship', 'Fresher', 'Contract'];
const CATEGORIES = ['Agriculture', 'Education', 'IT & Software', 'Healthcare', 'Construction', 'Textiles', 'Transport', 'Finance'];
const SALARY_RANGES = ['0–10k', '10k–20k', '20k–35k', '35k–60k', '60k+'];

interface Job {
  id: string;
  title: string;
  company: string;
  location: string;
  salary: string;
  salaryMin?: number;
  salaryMax?: number;
  type: string;
  posted: string;
  logo: string;
  isUrgent: boolean;
  isPremium: boolean;
  isVerified: boolean;
  category: string;
  skills: string[];
  openings: number;
}

function formatTime(timestamp: any) {
  if (!timestamp) return 'Recently';
  const date = timestamp.toMillis ? timestamp.toMillis() : new Date(timestamp).getTime();
  const seconds = Math.floor((Date.now() - date) / 1000);
  let interval = Math.floor(seconds / 31536000);
  if (interval >= 1) return interval + ' yr ago';
  interval = Math.floor(seconds / 2592000);
  if (interval >= 1) return interval + ' mo ago';
  interval = Math.floor(seconds / 86400);
  if (interval >= 1) return interval + ' d ago';
  interval = Math.floor(seconds / 3600);
  if (interval >= 1) return interval + ' hr ago';
  interval = Math.floor(seconds / 60);
  if (interval >= 1) return interval + ' min ago';
  return 'Just now';
}

export default function JobsPage() {
  const { user } = useAuth();
  const [search, setSearch] = useState('');
  const [location, setLocation] = useState('');
  const [selectedTypes, setSelectedTypes] = useState<string[]>([]);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showFilters, setShowFilters] = useState(false);
  const [savedJobs, setSavedJobs] = useState<string[]>([]);
  const [sortBy, setSortBy] = useState('latest');
  const [jobs, setJobs] = useState<Job[]>([]);
  const [loading, setLoading] = useState(true);

  // Initialize search and location from URL parameters
  useEffect(() => {
    if (typeof window !== 'undefined') {
      const params = new URLSearchParams(window.location.search);
      const searchParam = params.get('search');
      const locationParam = params.get('location');
      if (searchParam) setSearch(searchParam);
      if (locationParam) setLocation(locationParam);
    }
  }, []);

  // Fetch jobs from Firestore
  useEffect(() => {
    async function loadJobs() {
      try {
        const q = query(collection(db, 'jobs'), where('status', 'in', ['active', 'approved']));
        const snapshot = await getDocs(q);
        const data = snapshot.docs.map(doc => {
          const d = doc.data();
          const salaryStr = d.salaryMin && d.salaryMax 
            ? `₹${Number(d.salaryMin).toLocaleString('en-IN')} - ₹${Number(d.salaryMax).toLocaleString('en-IN')}`
            : 'Salary Negotiable';

          const typeStr = d.jobType 
            ? d.jobType.replace('_', ' ').split(' ').map((w: string) => w[0].toUpperCase() + w.substring(1)).join(' ')
            : 'Full Time';

          return {
            id: doc.id,
            title: d.title || '',
            company: d.companyName || 'Verified Employer',
            location: d.location || d.district || 'Theni',
            salary: salaryStr,
            salaryMin: d.salaryMin || 0,
            salaryMax: d.salaryMax || 0,
            type: typeStr,
            posted: formatTime(d.createdAt),
            logo: d.logo || (d.companyName ? d.companyName.substring(0, 2).toUpperCase() : '💼'),
            isUrgent: d.isUrgent || false,
            isPremium: d.isPremium || false,
            isVerified: d.isVerified || false,
            category: d.category || '',
            skills: d.skills || [],
            openings: d.openings ? Number(d.openings) : 1,
          } as Job;
        });
        setJobs(data);
      } catch (err) {
        console.error('Error loading jobs:', err);
      } finally {
        setLoading(false);
      }
    }
    loadJobs();
  }, []);

  // Fetch saved jobs for the user
  useEffect(() => {
    const userId = user?.uid;
    if (!userId) {
      setSavedJobs([]);
      return;
    }
    async function loadSavedJobs() {
      try {
        const q = query(collection(db, 'savedJobs'), where('userId', '==', userId));
        const snap = await getDocs(q);
        const ids = snap.docs.map(doc => doc.data().jobId);
        setSavedJobs(ids);
      } catch (err) {
        console.error('Error loading saved jobs:', err);
      }
    }
    loadSavedJobs();
  }, [user?.uid]);

  const toggleType = (t: string) => setSelectedTypes(p => p.includes(t) ? p.filter(x => x !== t) : [...p, t]);
  const toggleCategory = (c: string) => setSelectedCategories(p => p.includes(c) ? p.filter(x => x !== c) : [...p, c]);

  const toggleSave = async (job: Job) => {
    if (!user?.uid) {
      alert('Please login to save jobs.');
      return;
    }
    const isCurrentlySaved = savedJobs.includes(job.id);
    try {
      if (isCurrentlySaved) {
        const q = query(
          collection(db, 'savedJobs'),
          where('userId', '==', user.uid),
          where('jobId', '==', job.id)
        );
        const snap = await getDocs(q);
        const batch = writeBatch(db);
        snap.docs.forEach(doc => {
          batch.delete(doc.ref);
        });
        await batch.commit();
        setSavedJobs(p => p.filter(x => x !== job.id));
      } else {
        await addDoc(collection(db, 'savedJobs'), {
          userId: user.uid,
          jobId: job.id,
          jobTitle: job.title,
          companyName: job.company,
          description: `Positions available at ${job.company}. Required skills: ${job.skills.join(', ')}`,
          district: job.location,
          jobType: job.type,
          salaryMin: job.salaryMin || 0,
          salaryMax: job.salaryMax || 0,
          savedAt: serverTimestamp()
        });
        setSavedJobs(p => [...p, job.id]);
      }
    } catch (err) {
      console.error('Failed to toggle save:', err);
      alert('Failed to save job.');
    }
  };

  const filtered = jobs.filter(j => {
    const q = search.toLowerCase();
    const matchSearch = !q || j.title.toLowerCase().includes(q) || j.company.toLowerCase().includes(q) || j.skills.some(s => s.toLowerCase().includes(q));
    const matchLoc = !location || j.location.toLowerCase().includes(location.toLowerCase());
    const matchType = selectedTypes.length === 0 || selectedTypes.includes(j.type);
    const matchCat = selectedCategories.length === 0 || selectedCategories.includes(j.category);
    return matchSearch && matchLoc && matchType && matchCat;
  });

  const activeFilters = selectedTypes.length + selectedCategories.length;


  return (
    <main className="min-h-screen bg-[#0a0a1a]">
      <Header />

      {/* Search Bar – Sticky */}
      <div className="sticky top-16 z-40 glass-nav border-b border-white/5 px-4 sm:px-6 py-3">
        <div className="max-w-5xl mx-auto flex gap-2">
          <div className="flex-1 flex items-center gap-2 search-input px-4 py-2.5">
            <Search size={15} className="text-gray-500 shrink-0" />
            <input value={search} onChange={e => setSearch(e.target.value)}
              type="text" placeholder="Job title, skill, company..."
              className="flex-1 bg-transparent text-sm text-white placeholder-gray-500 outline-none" />
            {search && <button onClick={() => setSearch('')}><X size={13} className="text-gray-500" /></button>}
          </div>
          <div className="flex items-center gap-2 search-input px-3 py-2.5">
            <MapPin size={14} className="text-violet-400 shrink-0" />
            <select value={location} onChange={e => setLocation(e.target.value)}
              className="bg-transparent text-sm text-gray-300 outline-none pr-1 w-24">
              <option value="">All Areas</option>
              {['Theni', 'Madurai', 'Dindigul', 'Coimbatore', 'Remote'].map(d => (
                <option key={d} value={d}>{d}</option>
              ))}
            </select>
          </div>
          <button onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-2xl text-sm font-medium transition-all border
              ${showFilters || activeFilters > 0 ? 'bg-violet-500/20 border-violet-500/40 text-violet-300' : 'bg-white/5 border-white/10 text-gray-400'}`}>
            <SlidersHorizontal size={15} />
            <span className="hidden sm:inline">Filters</span>
            {activeFilters > 0 && <span className="w-5 h-5 rounded-full bg-violet-600 text-white text-[10px] font-bold flex items-center justify-center">{activeFilters}</span>}
          </button>
        </div>

        {/* Filter Panel */}
        {showFilters && (
          <div className="max-w-5xl mx-auto mt-3 glass-card rounded-2xl p-4 border border-white/10">
            <div className="grid sm:grid-cols-2 gap-5">
              <div>
                <p className="text-xs font-semibold text-gray-400 mb-2">Job Type</p>
                <div className="flex flex-wrap gap-2">
                  {JOB_TYPES.map(t => (
                    <button key={t} onClick={() => toggleType(t)}
                      className={`px-3 py-1.5 rounded-xl text-xs font-medium border transition-all
                        ${selectedTypes.includes(t) ? 'bg-violet-500/20 border-violet-500/50 text-violet-300' : 'bg-white/5 border-white/10 text-gray-400 hover:text-white'}`}>
                      {t}
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <p className="text-xs font-semibold text-gray-400 mb-2">Category</p>
                <div className="flex flex-wrap gap-2">
                  {CATEGORIES.map(c => (
                    <button key={c} onClick={() => toggleCategory(c)}
                      className={`px-3 py-1.5 rounded-xl text-xs font-medium border transition-all
                        ${selectedCategories.includes(c) ? 'bg-cyan-500/20 border-cyan-500/50 text-cyan-300' : 'bg-white/5 border-white/10 text-gray-400 hover:text-white'}`}>
                      {c}
                    </button>
                  ))}
                </div>
              </div>
            </div>
            {activeFilters > 0 && (
              <button onClick={() => { setSelectedTypes([]); setSelectedCategories([]); }}
                className="mt-3 text-xs text-rose-400 hover:text-rose-300 flex items-center gap-1">
                <X size={11} /> Clear all filters
              </button>
            )}
          </div>
        )}
      </div>

      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-6 pb-28 md:pb-12">
        {/* Results Header */}
        <div className="flex items-center justify-between mb-5">
          <div>
            <h1 className="font-outfit font-bold text-xl text-white">
              {filtered.length} Jobs Found
            </h1>
            <p className="text-sm text-gray-500 mt-0.5">
              {search ? `Results for "${search}"` : 'All available positions'}
              {location ? ` in ${location}` : ''}
            </p>
          </div>
          <div className="flex items-center gap-2 text-sm text-gray-400">
            <span className="hidden sm:inline text-xs">Sort:</span>
            <select value={sortBy} onChange={e => setSortBy(e.target.value)}
              className="bg-white/5 border border-white/10 rounded-xl px-3 py-1.5 text-xs text-gray-300 outline-none">
              <option value="latest">Latest</option>
              <option value="salary">Salary</option>
              <option value="relevance">Relevance</option>
            </select>
          </div>
        </div>

        {/* Job Cards */}
        <div className="space-y-3">
          {loading ? (
            <div className="glass-card rounded-2xl p-12 text-center">
              <Loader2 size={32} className="animate-spin text-violet-500 mx-auto mb-3" />
              <p className="text-gray-400 text-sm">Loading jobs...</p>
            </div>
          ) : filtered.length === 0 ? (
            <div className="glass-card rounded-2xl p-12 text-center">
              <div className="text-5xl mb-4">🔍</div>
              <h3 className="text-lg font-semibold text-white mb-2">No jobs found</h3>
              <p className="text-gray-400 text-sm">Try adjusting your search or filters</p>
              <button onClick={() => { setSearch(''); setSelectedTypes([]); setSelectedCategories([]); setLocation(''); }}
                className="mt-4 btn-outline-glass px-5 py-2 rounded-xl text-sm font-medium">
                Clear Filters
              </button>
            </div>
          ) : (
            filtered.map(job => (
