        </div>
      </div>

      <BottomNav />
    </main>
  );
}

'use client';

import { Suspense, useState, useEffect, useRef } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { Eye, EyeOff, Mail, Lock, Phone, ArrowRight, Loader2, AlertCircle } from 'lucide-react';
import { GoogleIcon } from '@/components/ui/BrandIcons';
import { useAuth } from '@/contexts/AuthContext';
import type { ConfirmationResult } from 'firebase/auth';

type AuthMode = 'email' | 'phone';

export default function LoginPage() {
  return (
    <Suspense fallback={<div className="min-h-screen bg-[#0a0a1a]" />}>
      <LoginPageContent />
    </Suspense>
  );
}

function LoginPageContent() {
  const router = useRouter();
  const [redirectUrl, setRedirectUrl] = useState('');

  useEffect(() => {
    if (typeof window !== 'undefined') {
      const params = new URLSearchParams(window.location.search);
      const redirect = params.get('redirect');
      if (redirect) {
        setRedirectUrl(redirect);
      }
    }
  }, []);

  const {
    user,
    loading: authLoading,
    error: authError,
    signInWithEmail,
    signInWithGoogle,
    sendPhoneOTP,
    verifyPhoneOTP,
    clearError
  } = useAuth();

  const [mode, setMode] = useState<AuthMode>('email');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<'input' | 'otp'>('input');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [localError, setLocalError] = useState<string | null>(null);

  const confirmationResultRef = useRef<ConfirmationResult | null>(null);

  // Clear errors on mode switch
  useEffect(() => {
    clearError();
    setLocalError(null);
  }, [mode, clearError]);

  // Role-based automatic redirect after successful login
  useEffect(() => {
    if (user) {
      if (redirectUrl) {
        router.push(redirectUrl);
      } else if (user.role === 'admin' || user.role === 'super_admin') {
        router.push('/admin/dashboard');
      } else if (user.role === 'employer' || user.role === 'business_owner') {
        router.push('/employer/dashboard');
      } else {
        router.push('/seeker/dashboard');
      }
    }
  }, [user, router, redirectUrl]);

  const handleOtpChange = (i: number, val: string) => {
    if (!/^\d?$/.test(val)) return;
    const next = [...otp];
    next[i] = val;
    setOtp(next);
    if (val && i < 5) {
      document.getElementById(`otp-${i + 1}`)?.focus();
    }
  };

  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setLocalError(null);
    try {
      await signInWithEmail(email, password);
    } catch (err: any) {
      console.error(err);
      setLocalError(err.message || 'Login failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  const handlePhoneSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) {
      setLocalError('Please enter a valid 10-digit mobile number.');
      return;
    }
    setLoading(true);
    setLocalError(null);
    try {
      const formattedPhone = `+91${phone}`;
      const confirmation = await sendPhoneOTP(formattedPhone, 'recaptcha-container');
      confirmationResultRef.current = confirmation;
      setStep('otp');
    } catch (err: any) {
      console.error(err);
      setLocalError(err.message || 'Failed to send OTP. Please check your number.');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    const fullOtp = otp.join('');
    if (fullOtp.length !== 6) {
      setLocalError('Please enter the 6-digit OTP.');
      return;
    }
    if (!confirmationResultRef.current) {
      setLocalError('Session expired. Please request OTP again.');
      setStep('input');
      return;
    }
    setLoading(true);
    setLocalError(null);
    try {
      await verifyPhoneOTP(confirmationResultRef.current, fullOtp);
    } catch (err: any) {
      console.error(err);
      setLocalError(err.message || 'Invalid OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setLoading(true);
    setLocalError(null);
    try {
      await signInWithGoogle();
    } catch (err: any) {
      console.error(err);
      setLocalError(err.message || 'Google Sign-in failed.');
    } finally {
      setLoading(false);
    }
  };

  const activeError = localError || authError;

  return (
    <div className="min-h-screen bg-[#0a0a1a] flex items-center justify-center px-4 blob-bg grid-pattern">
      {/* Invisible Recaptcha Container */}
      <div id="recaptcha-container"></div>

      <div className="w-full max-w-sm">
        {/* Logo */}
        <Link href="/" className="flex items-center gap-2 justify-center mb-8">
          <img src="/logo.png" alt="THENIJOBS Logo" className="h-10 w-auto object-contain" />
        </Link>

        <div className="glass-card rounded-3xl p-7 shadow-2xl">
          <h1 className="text-2xl font-outfit font-bold text-white text-center mb-1">Welcome back</h1>
          <p className="text-gray-400 text-sm text-center mb-7">Sign in to your account</p>

          {activeError && (
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-xl bg-rose-500/10 border border-rose-500/15 mb-4">
              <AlertCircle size={14} className="text-rose-400 flex-shrink-0" />
              <p className="text-[11px] text-rose-300">{activeError}</p>
            </div>
          )}

          {/* Mode Toggle */}
          <div className="flex rounded-2xl bg-white/5 p-1 gap-1 mb-6">
            {(['email', 'phone'] as AuthMode[]).map(m => (
              <button key={m} onClick={() => { setMode(m); setStep('input'); }}
                className={`flex-1 py-2.5 rounded-xl text-sm font-semibold capitalize transition-all
                  ${mode === m ? 'bg-violet-600 text-white' : 'text-gray-400 hover:text-white'}`}>
                {m === 'email' ? '📧 Email' : '📱 Mobile OTP'}
              </button>
            ))}
          </div>

          {step === 'input' ? (
            <form onSubmit={mode === 'email' ? handleEmailLogin : handlePhoneSubmit} className="space-y-4">
              {mode === 'email' ? (
                <>
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-medium">Email Address</label>
                    <div className="relative">
                      <Mail size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
                      <input type="email" required placeholder="your@email.com"
                        value={email} onChange={e => setEmail(e.target.value)}
                        className="search-input w-full pl-10 pr-4 py-3 text-sm" />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-medium">Password</label>
                    <div className="relative">
                      <Lock size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
                      <input type={showPass ? 'text' : 'password'} required placeholder="••••••••"
                        value={password} onChange={e => setPassword(e.target.value)}
                        className="search-input w-full pl-10 pr-10 py-3 text-sm" />
                      <button type="button" onClick={() => setShowPass(!showPass)}
                        className="absolute right-3.5 top-1/2 -translate-y-1/2 text-gray-500 hover:text-white transition-colors">
                        {showPass ? <EyeOff size={15} /> : <Eye size={15} />}
                      </button>
                    </div>
                  </div>
                  <div className="flex justify-end">
                    <Link href="/forgot-password" className="text-xs text-violet-400 hover:text-violet-300 transition-colors">
                      Forgot password?
                    </Link>
                  </div>
                </>
              ) : (
                <div className="space-y-1">
                  <label className="text-xs text-gray-400 font-medium">Mobile Number</label>
                  <div className="flex gap-2">
                    <div className="search-input px-3 py-3 text-sm text-gray-400 w-16 text-center rounded-xl">+91</div>
                    <div className="relative flex-1">
                      <Phone size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
                      <input type="tel" required maxLength={10} placeholder="98765 43210"
                        value={phone} onChange={e => setPhone(e.target.value)}
                        className="search-input w-full pl-10 pr-4 py-3 text-sm" />
                    </div>
                  </div>
                </div>
              )}

              <button type="submit" disabled={loading}
                className="w-full btn-gradient py-3.5 rounded-2xl font-semibold text-sm relative z-10 flex items-center justify-center gap-2 mt-2">
                {loading ? <Loader2 size={16} className="animate-spin" /> : null}
                {mode === 'phone' ? 'Send OTP' : 'Sign In'}
                {!loading && <ArrowRight size={15} />}
              </button>

              <div className="relative flex items-center gap-3 py-1">
                <div className="flex-1 gradient-divider" />
                <span className="text-xs text-gray-600">or</span>
                <div className="flex-1 gradient-divider" />
              </div>

              <button type="button" onClick={handleGoogleLogin} disabled={loading}
                className="w-full btn-outline-glass py-3 rounded-2xl text-sm font-medium flex items-center justify-center gap-2">
                <GoogleIcon size={16} />
                Continue with Google
              </button>
            </form>
          ) : (
            /* OTP Screen */
            <div className="space-y-6">
              <div className="text-center">
                <div className="text-3xl mb-2">📱</div>
                <p className="text-sm text-gray-300">OTP sent to your mobile</p>
                <p className="text-xs text-gray-500 mt-1">Enter the 6-digit code below</p>
              </div>
              <div className="flex justify-center gap-2">
                {otp.map((digit, i) => (
                  <input key={i} id={`otp-${i}`} type="text" maxLength={1} value={digit}
                    onChange={e => handleOtpChange(i, e.target.value)}
                    className="w-11 h-12 text-center text-white text-lg font-bold rounded-xl bg-white/5 border border-white/15 focus:border-violet-500 focus:bg-white/8 outline-none transition-all" />
                ))}
              </div>
              <button onClick={handleVerifyOtp} disabled={loading}
                className="w-full btn-gradient py-3.5 rounded-2xl font-semibold text-sm relative z-10 flex items-center justify-center gap-2">
                {loading ? <Loader2 size={16} className="animate-spin" /> : 'Verify OTP'}
              </button>
              <p className="text-center text-xs text-gray-500">
                Didn&apos;t receive? <button className="text-violet-400 hover:text-violet-300">Resend OTP</button>
              </p>
            </div>
          )}

          <p className="text-center text-sm text-gray-500 mt-6">
            Don&apos;t have an account?{' '}
            <Link href="/register" className="text-violet-400 hover:text-violet-300 font-medium transition-colors">
              Join Free
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import {
  ArrowRight, ArrowLeft, Check, Briefcase, Building2,
  Package, Wrench, Users, Loader2, User, Phone, Mail, Lock, AlertCircle
} from 'lucide-react';
import { GoogleIcon } from '@/components/ui/BrandIcons';
import { useAuth } from '@/contexts/AuthContext';
import { doc, updateDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase/config';
import type { UserRole } from '@/lib/types';

const ROLES = [
  { id: 'job_seeker', label: 'Job Seeker', subLabel: 'வேலை தேடுகிறேன்', icon: Briefcase, desc: 'Find jobs, build resume, track applications', color: 'violet' },
  { id: 'employer', label: 'Employer / HR', subLabel: 'ஆட்களை எடுக்கிறேன்', icon: Building2, desc: 'Post jobs, search candidates, hire talent', color: 'cyan' },
  { id: 'business_owner', label: 'Business Owner', subLabel: 'Business வைத்திருக்கிறேன்', icon: Users, desc: 'List your business, get leads & enquiries', color: 'emerald' },
  { id: 'supplier', label: 'Supplier / B2B', subLabel: 'Products விற்கிறேன்', icon: Package, desc: 'List products, receive RFQs from buyers', color: 'amber' },
  { id: 'service_provider', label: 'Service Provider', subLabel: 'Service வழங்குகிறேன்', icon: Wrench, desc: 'Offer services, get bookings & reviews', color: 'rose' },
];

const colorMap: Record<string, string> = {
  violet: 'border-violet-500 bg-violet-500/10',
  cyan: 'border-cyan-500 bg-cyan-500/10',
  emerald: 'border-emerald-500 bg-emerald-500/10',
  amber: 'border-amber-500 bg-amber-500/10',
  rose: 'border-rose-500 bg-rose-500/10',
};

const iconColorMap: Record<string, string> = {
  violet: 'text-violet-400', cyan: 'text-cyan-400',
  emerald: 'text-emerald-400', amber: 'text-amber-400', rose: 'text-rose-400',
};

export default function RegisterPage() {
  const router = useRouter();
  const { user, createAccount, signInWithGoogle, error: authError, clearError } = useAuth();

  const [step, setStep] = useState(1);
  const [role, setRole] = useState('');
  const [loading, setLoading] = useState(false);
  const [localError, setLocalError] = useState<string | null>(null);
  const [form, setForm] = useState({ name: '', phone: '', email: '', password: '' });

  const totalSteps = 2; // Reduced to 2 steps since Email signup does not require a fake OTP step

  // Redirect automatically on login / registration success
  useEffect(() => {
    if (user) {
      if (user.role === 'admin' || user.role === 'super_admin') {
        router.push('/admin/dashboard');
      } else if (user.role === 'employer' || user.role === 'business_owner') {
        router.push('/employer/dashboard');
      } else {
        router.push('/seeker/dashboard');
      }
    }
  }, [user, router]);

  useEffect(() => {
    clearError();
    setLocalError(null);
  }, [step, clearError]);

  const handleGoogleRegister = async () => {
    setLoading(true);
    setLocalError(null);
    try {
      await signInWithGoogle();
    } catch (err: any) {
      console.error(err);
      setLocalError(err.message || 'Google registration failed.');
    } finally {
      setLoading(false);
    }
  };

  const next = async () => {
    setLocalError(null);
    if (step === 1) {
      if (!role) {
        setLocalError('Please select a role to continue.');
        return;
      }
      setStep(2);
      return;
    }

    if (step === 2) {
      if (!form.name || !form.email || !form.password) {
        setLocalError('Please fill in all required fields.');
        return;
      }
      if (form.password.length < 6) {
        setLocalError('Password must be at least 6 characters.');
        return;
      }

      setLoading(true);
      try {
        await createAccount(form.email, form.password, form.name, role as UserRole);
        // Save phone number if provided
        if (form.phone && user?.uid) {
          await updateDoc(doc(db, 'users', user.uid), {
            phone: `+91${form.phone}`
          });
        }
      } catch (err: any) {
        console.error(err);
        setLocalError(err.message || 'Registration failed. Please try again.');
      } finally {
        setLoading(false);
      }
    }
  };

  const activeError = localError || authError;

  return (
    <div className="min-h-screen bg-[#0a0a1a] flex items-center justify-center px-4 blob-bg grid-pattern py-10">
      <div className="w-full max-w-lg">
        {/* Logo */}
        <Link href="/" className="flex items-center gap-2 justify-center mb-8">
          <img src="/logo.png" alt="THENIJOBS Logo" className="h-10 w-auto object-contain" />
        </Link>

        <div className="glass-card rounded-3xl p-7 shadow-2xl">
          {/* Progress */}
          <div className="flex items-center gap-2 mb-7">
            {Array.from({ length: totalSteps }).map((_, i) => (
              <div key={i} className="flex items-center flex-1 gap-2">
                <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold shrink-0 transition-all
                  ${i + 1 < step ? 'bg-emerald-500 text-white' : i + 1 === step ? 'bg-violet-600 text-white' : 'bg-white/10 text-gray-500'}`}>
                  {i + 1 < step ? <Check size={13} /> : i + 1}
                </div>
                {i < totalSteps - 1 && (
                  <div className={`flex-1 h-0.5 rounded-full ${i + 1 < step ? 'bg-emerald-500' : 'bg-white/10'}`} />
                )}
              </div>
            ))}
          </div>

          {activeError && (
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-xl bg-rose-500/10 border border-rose-500/15 mb-5">
              <AlertCircle size={14} className="text-rose-400 flex-shrink-0" />
              <p className="text-[11px] text-rose-300">{activeError}</p>
            </div>
          )}

          {/* STEP 1 — Role Selection */}
          {step === 1 && (
            <div>
              <h1 className="text-xl font-outfit font-bold text-white mb-1">I am a...</h1>
              <p className="text-gray-400 text-sm mb-5">Select your role to get a personalised experience</p>
              <div className="space-y-2.5">
                {ROLES.map(r => (
                  <button key={r.id} onClick={() => setRole(r.id)}
                    className={`w-full flex items-center gap-4 p-4 rounded-2xl border transition-all text-left
                      ${role === r.id ? `${colorMap[r.color]} border` : 'bg-white/3 border-white/10 hover:bg-white/5'}`}>
                    <div className={`w-11 h-11 rounded-xl flex items-center justify-center shrink-0
                      ${role === r.id ? `bg-${r.color}-500/20` : 'bg-white/5'}`}>
                      <r.icon size={20} className={role === r.id ? iconColorMap[r.color] : 'text-gray-500'} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-white text-sm">{r.label}</div>
                      <div className="text-xs text-gray-500">{r.subLabel}</div>
                      <div className="text-xs text-gray-600 mt-0.5">{r.desc}</div>
                    </div>
                    {role === r.id && <Check size={16} className={iconColorMap[r.color]} />}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* STEP 2 — Basic Details */}
          {step === 2 && (
            <div>
              <h1 className="text-xl font-outfit font-bold text-white mb-1">Create Account</h1>
              <p className="text-gray-400 text-sm mb-5">Fill in your basic details</p>
              <div className="space-y-4">
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Full Name *</label>
                  <div className="relative">
                    <User size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
                    <input type="text" placeholder="Your full name" value={form.name}
                      onChange={e => setForm({ ...form, name: e.target.value })}
                      className="search-input w-full pl-10 pr-4 py-3 text-sm" />
                  </div>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Mobile Number</label>
                  <div className="flex gap-2">
                    <div className="search-input px-3 py-3 text-sm text-gray-400 w-16 text-center rounded-xl">+91</div>
                    <div className="relative flex-1">
                      <Phone size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
                      <input type="tel" maxLength={10} placeholder="98765 43210" value={form.phone}
                        onChange={e => setForm({ ...form, phone: e.target.value })}
                        className="search-input w-full pl-10 pr-4 py-3 text-sm" />
                    </div>
                  </div>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Email Address *</label>
                  <div className="relative">
                    <Mail size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
                    <input type="email" placeholder="your@email.com" value={form.email}
                      onChange={e => setForm({ ...form, email: e.target.value })}
                      className="search-input w-full pl-10 pr-4 py-3 text-sm" />
                  </div>
                </div>
                <div>
                  <label className="text-xs text-gray-400 font-medium block mb-1.5">Password *</label>
                  <div className="relative">
                    <Lock size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
                    <input type="password" placeholder="Min. 6 characters" value={form.password}
                      onChange={e => setForm({ ...form, password: e.target.value })}
                      className="search-input w-full pl-10 pr-4 py-3 text-sm" />
                  </div>
                </div>

                <div className="relative flex items-center gap-3 py-1">
                  <div className="flex-1 gradient-divider" />
                  <span className="text-xs text-gray-600">or</span>
                  <div className="flex-1 gradient-divider" />
                </div>
                <button type="button" onClick={handleGoogleRegister} disabled={loading}
                  className="w-full btn-outline-glass py-3 rounded-2xl text-sm font-medium flex items-center justify-center gap-2">
                  <GoogleIcon size={16} /> Continue with Google
                </button>
              </div>
            </div>
          )}

          {/* Navigation Buttons */}
          <div className="flex gap-3 mt-6">
            {step > 1 && (
              <button onClick={() => setStep(s => s - 1)}
                className="btn-outline-glass px-5 py-3 rounded-2xl text-sm font-semibold flex items-center gap-2">
                <ArrowLeft size={15} /> Back
              </button>
            )}
            <button onClick={next} disabled={(step === 1 && !role) || loading}
              className="flex-1 btn-gradient py-3 rounded-2xl font-semibold text-sm relative z-10 flex items-center justify-center gap-2 disabled:opacity-40 disabled:cursor-not-allowed">
              {loading ? <Loader2 size={16} className="animate-spin" /> : null}
              {step === totalSteps ? 'Create Account' : 'Continue'}
              {!loading && <ArrowRight size={15} />}
            </button>
          </div>

          {step === 1 && (
            <p className="text-center text-sm text-gray-500 mt-5">
              Already have an account?{' '}
              <Link href="/login" className="text-violet-400 hover:text-violet-300 font-medium transition-colors">Sign In</Link>
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import {
  User, Phone, Mail, MapPin, Camera, Briefcase, GraduationCap,
  Plus, X, Check, Save, Globe, Award, Star, Zap,
  CheckCircle, Circle, Languages, ExternalLink, Loader2
} from 'lucide-react';
import { TN_DISTRICTS } from '@/lib/types';
import { useAuth } from '@/hooks/useAuth';
import { useDocument } from '@/hooks/useFirestore';
import { useUploadFile } from '@/hooks/useStorage';
import { db } from '@/lib/firebase/config';
import { setDoc, doc, serverTimestamp } from 'firebase/firestore';

/** Skill suggestions for tag input */
const SKILL_SUGGESTIONS = [
  'Driving License', 'Tractor Driving', 'Tally', 'Excel', 'GST Filing',
  'English Speaking', 'Communication', 'Team Work', 'Agriculture', 'Computer',
  'Accounting', 'Sales', 'Marketing', 'Welding', 'Electrical', 'Plumbing',
  'AutoCAD', 'Data Entry', 'Customer Service', 'Machine Operation'
];

const LANGUAGE_OPTIONS = ['Tamil', 'English', 'Hindi', 'Telugu', 'Malayalam', 'Kannada', 'Urdu', 'Sanskrit', 'French'];

interface EducationEntry {
  id: string;
  institution: string;
  degree: string;
  field: string;
  year: string;
}

interface ExperienceEntry {
  id: string;
  company: string;
  role: string;
  startDate: string;
  endDate: string;
  description: string;
}

interface CertificationEntry {
  id: string;
  name: string;
  organization: string;
  date: string;
  link: string;
}

type TabKey = 'personal' | 'education' | 'experience' | 'skills' | 'languages' | 'certifications' | 'portfolio';

const DEFAULT_PROFILE = {
  name: '',
  dob: '',
  gender: 'Male',
  phone: '',
  email: '',
  address: '',
  district: '',
  currentRole: '',
  isOpenToWork: true,
  photoUrl: ''
};

export default function SeekerProfilePage() {
  const { user } = useAuth();

  // 1. Fetch profile from Firestore
  const { data: remoteProfile, loading: profileLoading } = useDocument<any>('seekerProfiles', user?.uid);

  const [profile, setProfile] = useState(DEFAULT_PROFILE);
  const [education, setEducation] = useState<EducationEntry[]>([]);
  const [experience, setExperience] = useState<ExperienceEntry[]>([]);
  const [skills, setSkills] = useState<string[]>([]);
  const [languages, setLanguages] = useState<string[]>([]);
  const [certifications, setCertifications] = useState<CertificationEntry[]>([]);
  const [portfolio, setPortfolio] = useState<string[]>([]);

  const [newSkill, setNewSkill] = useState('');
  const [newPortfolioLink, setNewPortfolioLink] = useState('');
  const [activeTab, setActiveTab] = useState<TabKey>('personal');
  const [saving, setSaving] = useState(false);

  const avatarInputRef = useRef<HTMLInputElement>(null);
  const { uploadFile, progress: uploadProgress, loading: uploading } = useUploadFile();

  // Populate data when fetched
  useEffect(() => {
    if (remoteProfile) {
      setProfile({
        name: remoteProfile.name || '',
        dob: remoteProfile.dob || '',
        gender: remoteProfile.gender || 'Male',
        phone: remoteProfile.phone || '',
        email: remoteProfile.email || '',
        address: remoteProfile.address || '',
        district: remoteProfile.district || '',
        currentRole: remoteProfile.currentRole || '',
        isOpenToWork: remoteProfile.isOpenToWork !== false,
        photoUrl: remoteProfile.photoUrl || ''
      });
      setEducation(remoteProfile.education || []);
      setExperience(remoteProfile.experience || []);
      setSkills(remoteProfile.skills || []);
      setLanguages(remoteProfile.languages || []);
      setCertifications(remoteProfile.certifications || []);
      setPortfolio(remoteProfile.portfolio || []);
    } else if (user) {
      setProfile(p => ({
        ...p,
        name: user.displayName || '',
        email: user.email || '',
        phone: user.phone || ''
      }));
    }
  }, [remoteProfile, user]);

  // ── Profile Strength ──
  const strengthItems = [
    { label: 'Photo uploaded', done: !!profile.photoUrl },
    { label: 'Contact details', done: !!profile.phone && !!profile.email },
    { label: 'Education added', done: education.length > 0 },
    { label: 'Experience added', done: experience.length > 0 },
    { label: 'Skills added', done: skills.length >= 3 },
    { label: 'Languages selected', done: languages.length > 0 },
    { label: 'Certifications', done: certifications.length > 0 },
    { label: 'Portfolio links', done: portfolio.length > 0 },
  ];
  const profileStrength = Math.round((strengthItems.filter(i => i.done).length / strengthItems.length) * 100);

  // ── Handlers ──
  const addSkill = () => {
    if (newSkill.trim() && !skills.includes(newSkill.trim())) {
      setSkills(s => [...s, newSkill.trim()]);
      setNewSkill('');
    }
  };

  const addEducation = () => {
    setEducation(e => [...e, { id: Date.now().toString(), institution: '', degree: '', field: '', year: '' }]);
  };

  const removeEducation = (id: string) => {
    setEducation(e => e.filter(item => item.id !== id));
  };

  const updateEducation = (id: string, key: keyof EducationEntry, value: string) => {
    setEducation(e => e.map(item => item.id === id ? { ...item, [key]: value } : item));
  };

  const addExperience = () => {
    setExperience(e => [...e, { id: Date.now().toString(), company: '', role: '', startDate: '', endDate: '', description: '' }]);
  };

  const removeExperience = (id: string) => {
    setExperience(e => e.filter(item => item.id !== id));
  };

  const updateExperience = (id: string, key: keyof ExperienceEntry, value: string) => {
    setExperience(e => e.map(item => item.id === id ? { ...item, [key]: value } : item));
  };

  const addCertification = () => {
    setCertifications(c => [...c, { id: Date.now().toString(), name: '', organization: '', date: '', link: '' }]);
  };

  const removeCertification = (id: string) => {
    setCertifications(c => c.filter(item => item.id !== id));
  };

  const updateCertification = (id: string, key: keyof CertificationEntry, value: string) => {
    setCertifications(c => c.map(item => item.id === id ? { ...item, [key]: value } : item));
  };

  const addPortfolioLink = () => {
    if (newPortfolioLink.trim()) {
      setPortfolio(p => [...p, newPortfolioLink.trim()]);
      setNewPortfolioLink('');
    }
  };

  const handleUploadAvatar = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user?.uid) return;
    try {
      const url = await uploadFile(file, `users/${user.uid}/profile/avatar_${Date.now()}_${file.name}`);
      setProfile(p => ({ ...p, photoUrl: url }));
    } catch (err) {
      console.error(err);
      alert('Upload failed: ' + (err as Error).message);
    }
  };

  const handleSaveProfile = async () => {
    if (!user?.uid) return;
    if (!profile.name || !profile.email || !profile.phone) {
      alert('Please fill in Name, Email, and Phone number.');
      return;
    }

    setSaving(true);
    try {
      const profileData = {
        ...profile,
        education,
        experience,
        skills,
        languages,
        certifications,
        portfolio,
        profileStrength,
        updatedAt: serverTimestamp()
      };

      // Write to seekerProfiles
      await setDoc(doc(db, 'seekerProfiles', user.uid), profileData, { merge: true });

      // Sync key details back to users collection
      await setDoc(doc(db, 'users', user.uid), {
        displayName: profile.name,
        email: profile.email,
        phone: profile.phone,
        district: profile.district,
        updatedAt: serverTimestamp()
      }, { merge: true });

      alert('Profile saved successfully!');
    } catch (err) {
      console.error(err);
      alert('Failed to save profile details.');
    } finally {
      setSaving(false);
    }
  };

  const tabs: { key: TabKey; label: string; icon: React.ElementType }[] = [
    { key: 'personal', label: 'Personal', icon: User },
    { key: 'education', label: 'Education', icon: GraduationCap },
    { key: 'experience', label: 'Experience', icon: Briefcase },
    { key: 'skills', label: 'Skills', icon: Star },
    { key: 'languages', label: 'Languages', icon: Languages },
    { key: 'certifications', label: 'Certifications', icon: Award },
    { key: 'portfolio', label: 'Portfolio', icon: Globe },
  ];

  if (profileLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 font-outfit text-white">
        <Loader2 size={36} className="text-emerald-400 animate-spin mb-4" />
        <p className="text-sm text-gray-400">Loading your profile...</p>
      </div>
    );
  }

  const initials = profile.name ? profile.name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) : 'AS';

  return (
    <div className="animate-fade-in-up space-y-6 max-w-4xl mx-auto font-outfit text-white">
      {/* Uploading progress notification */}
      {uploading && (
        <div className="glass-card rounded-2xl p-4 border border-emerald-500/20 bg-emerald-500/5 flex items-center gap-3">
          <Loader2 size={18} className="text-emerald-400 animate-spin" />
          <span className="text-xs text-gray-300">Uploading avatar... {uploadProgress}%</span>
        </div>
      )}

      {/* ═══ Profile Header ═══ */}
      <div className="glass-card rounded-2xl p-6 relative overflow-hidden">
        <div className="absolute inset-0 grid-pattern opacity-10" />
        <div className="relative z-10 flex flex-col sm:flex-row items-start gap-5">
          {/* Avatar */}
          <div className="relative shrink-0 self-center sm:self-start">
            <div className="w-24 h-24 rounded-2xl bg-gradient-to-br from-emerald-500 to-cyan-500 flex items-center justify-center text-3xl font-bold text-white shadow-xl overflow-hidden">
              {profile.photoUrl ? (
                <img src={profile.photoUrl} alt="Avatar" className="w-full h-full object-cover" />
              ) : (
                initials
              )}
            </div>
            <button
              onClick={() => avatarInputRef.current?.click()}
              className="absolute -bottom-1.5 -right-1.5 w-8 h-8 rounded-xl bg-violet-600 border-2 border-[#0a0a1a] flex items-center justify-center hover:bg-violet-500 transition-colors"
            >
              <Camera size={14} className="text-white" />
            </button>
            <input ref={avatarInputRef} type="file" accept="image/*" className="hidden" onChange={handleUploadAvatar} />
          </div>

          {/* Info */}
          <div className="flex-1 min-w-0 w-full">
            <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-3">
              <div>
                <h1 className="text-xl font-outfit font-bold text-white">{profile.name || 'Set Your Name'}</h1>
                <p className="text-emerald-400 text-sm font-medium">{profile.currentRole || 'Specify Current Role'}</p>
                <div className="flex items-center gap-1.5 mt-1 text-xs text-gray-400">
                  <MapPin size={11} /> {profile.district || 'Select district'}, Tamil Nadu
                </div>
              </div>
              {/* Open to Work Toggle */}
              <div className="flex flex-col items-start sm:items-end gap-2">
                <label className="flex items-center gap-2 cursor-pointer">
                  <span className="text-xs text-gray-400">Open to Work</span>
                  <div
                    onClick={() => setProfile(p => ({ ...p, isOpenToWork: !p.isOpenToWork }))}
                    className={`w-10 h-5.5 rounded-full relative transition-all cursor-pointer ${profile.isOpenToWork ? 'bg-emerald-500' : 'bg-white/20'}`}
                  >
                    <div className={`w-4 h-4 rounded-full bg-white absolute top-[3px] transition-all ${profile.isOpenToWork ? 'left-[22px]' : 'left-[3px]'}`} />
                  </div>
                </label>
                {profile.isOpenToWork && (
                  <span className="text-[10px] px-2.5 py-0.5 rounded-full bg-emerald-500/15 text-emerald-400 border border-emerald-500/20 font-bold">
                    ● Open to Work
                  </span>
                )}
              </div>
            </div>

            {/* Contact row */}
            <div className="flex flex-wrap items-center gap-4 mt-3 text-xs text-gray-400">
              <span className="flex items-center gap-1"><Phone size={11} /> {profile.phone || 'No phone number'}</span>
              <span className="flex items-center gap-1"><Mail size={11} /> {profile.email}</span>
            </div>
          </div>
        </div>
      </div>

      {/* ═══ Profile Strength ═══ */}
      <div className="glass-card rounded-2xl p-5">
        <div className="flex items-center justify-between mb-3">
          <h2 className="font-semibold text-white text-sm flex items-center gap-2">
            <Zap size={15} className="text-emerald-400" /> Profile Strength
          </h2>
          <span className={`text-sm font-bold ${profileStrength >= 80 ? 'text-emerald-400' : profileStrength >= 60 ? 'text-amber-400' : 'text-rose-400'}`}>
            {profileStrength}%
          </span>
        </div>
        <div className="h-2 bg-white/10 rounded-full overflow-hidden mb-4">
          <div
            className="h-full bg-gradient-to-r from-emerald-500 to-cyan-500 rounded-full transition-all duration-700"
            style={{ width: `${profileStrength}%` }}
          />
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
          {strengthItems.map(item => (
            <div key={item.label} className="flex items-center gap-1.5 text-xs">
              {item.done ? (
                <CheckCircle size={13} className="text-emerald-400 shrink-0" />
              ) : (
                <Circle size={13} className="text-gray-600 shrink-0" />
              )}
              <span className={item.done ? 'text-gray-300' : 'text-gray-600'}>{item.label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ═══ Tabs ═══ */}
      <div className="flex gap-1.5 overflow-x-auto no-scrollbar pb-1">
        {tabs.map(tab => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.key;
          return (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`flex items-center gap-1.5 px-3.5 py-2 rounded-xl text-xs font-medium whitespace-nowrap transition-all ${
                isActive
                  ? 'bg-emerald-500/15 text-emerald-400 border border-emerald-500/25'
                  : 'bg-white/[0.03] text-gray-500 border border-white/[0.06] hover:bg-white/[0.06] hover:text-gray-300'
              }`}
            >
              <Icon size={13} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* ═══ Tab Content ═══ */}
      <div className="glass-card rounded-2xl p-5">
        {/* ── Personal Details ── */}
        {activeTab === 'personal' && (
          <div>
            <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-5">
              <User size={15} className="text-emerald-400" /> Personal Details
            </h2>
            <div className="grid sm:grid-cols-2 gap-4">
              {[
                { key: 'name', label: 'Full Name', type: 'text' },
                { key: 'dob', label: 'Date of Birth', type: 'date' },
                { key: 'gender', label: 'Gender', type: 'select', options: ['Male', 'Female', 'Other'] },
                { key: 'phone', label: 'Phone Number', type: 'tel' },
                { key: 'email', label: 'Email Address', type: 'email' },
                { key: 'currentRole', label: 'Current Role', type: 'text' },
              ].map(field => (
                <div key={field.key}>
                  <label className="text-xs text-gray-400 block mb-1.5">{field.label}</label>
                  {field.type === 'select' ? (
                    <select
                      value={(profile as any)[field.key]}
                      onChange={e => setProfile(p => ({ ...p, [field.key]: e.target.value }))}
                      className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]"
                    >
                      {field.options?.map(o => <option key={o} value={o}>{o}</option>)}
                    </select>
                  ) : (
                    <input
                      type={field.type}
                      value={(profile as any)[field.key]}
                      onChange={e => setProfile(p => ({ ...p, [field.key]: e.target.value }))}
                      className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]"
                    />
                  )}
                </div>
              ))}
              <div className="sm:col-span-2">
                <label className="text-xs text-gray-400 block mb-1.5">Address</label>
                <input
                  type="text"
                  value={profile.address}
                  onChange={e => setProfile(p => ({ ...p, address: e.target.value }))}
                  className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]"
                />
              </div>
              <div>
                <label className="text-xs text-gray-400 block mb-1.5">District</label>
                <select
                  value={profile.district}
                  onChange={e => setProfile(p => ({ ...p, district: e.target.value }))}
                  className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]"
                >
                  <option value="">Select district</option>
                  {TN_DISTRICTS.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {/* ── Education ── */}
        {activeTab === 'education' && (
          <div>
            <div className="flex items-center justify-between mb-5">
              <h2 className="font-semibold text-white text-sm flex items-center gap-2">
                <GraduationCap size={15} className="text-emerald-400" /> Education
              </h2>
              <button onClick={addEducation} className="flex items-center gap-1 text-xs text-emerald-400 hover:text-emerald-300 px-3 py-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/20 transition-all">
                <Plus size={12} /> Add Education
              </button>
            </div>
            <div className="space-y-4">
              {education.map((edu) => (
                <div key={edu.id} className="p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] relative group">
                  <button onClick={() => removeEducation(edu.id)} className="absolute top-3 right-3 p-1 rounded-lg text-gray-600 hover:text-rose-400 hover:bg-rose-500/10 transition-all opacity-0 group-hover:opacity-100">
                    <X size={14} />
                  </button>
                  <div className="grid sm:grid-cols-2 gap-3">
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">Institution</label>
                      <input type="text" value={edu.institution} onChange={e => updateEducation(edu.id, 'institution', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="Institution name" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">Degree</label>
                      <input type="text" value={edu.degree} onChange={e => updateEducation(edu.id, 'degree', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="e.g. B.Sc, 12th Standard" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">Field of Study</label>
                      <input type="text" value={edu.field} onChange={e => updateEducation(edu.id, 'field', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="e.g. Computer Science" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">Year</label>
                      <input type="text" value={edu.year} onChange={e => updateEducation(edu.id, 'year', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="e.g. 2020" />
                    </div>
                  </div>
                </div>
              ))}
              {education.length === 0 && (
                <div className="text-center py-10 text-gray-600 text-sm">
                  <GraduationCap size={32} className="mx-auto mb-2 opacity-40" />
                  No education entries yet. Click &quot;Add Education&quot; to get started.
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── Experience ── */}
        {activeTab === 'experience' && (
          <div>
            <div className="flex items-center justify-between mb-5">
              <h2 className="font-semibold text-white text-sm flex items-center gap-2">
                <Briefcase size={15} className="text-emerald-400" /> Work Experience
              </h2>
              <button onClick={addExperience} className="flex items-center gap-1 text-xs text-emerald-400 hover:text-emerald-300 px-3 py-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/25 transition-all">
                <Plus size={12} /> Add Experience
              </button>
            </div>
            <div className="space-y-4">
              {experience.map((exp) => (
                <div key={exp.id} className="p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] relative group">
                  <button onClick={() => removeExperience(exp.id)} className="absolute top-3 right-3 p-1 rounded-lg text-gray-600 hover:text-rose-400 hover:bg-rose-500/10 transition-all opacity-0 group-hover:opacity-100">
                    <X size={14} />
                  </button>
                  <div className="grid sm:grid-cols-2 gap-3">
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">Company</label>
                      <input type="text" value={exp.company} onChange={e => updateExperience(exp.id, 'company', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="Company name" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">Role / Title</label>
                      <input type="text" value={exp.role} onChange={e => updateExperience(exp.id, 'role', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="e.g. Web Developer" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">Start Date</label>
                      <input type="text" value={exp.startDate} onChange={e => updateExperience(exp.id, 'startDate', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="e.g. 2022-06" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-505 block mb-1">End Date</label>
                      <input type="text" value={exp.endDate} onChange={e => updateExperience(exp.id, 'endDate', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="Present or 2024-05" />
                    </div>
                    <div className="sm:col-span-2">
                      <label className="text-xs text-gray-505 block mb-1">Description</label>
                      <textarea rows={2} value={exp.description} onChange={e => updateExperience(exp.id, 'description', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22] resize-none" placeholder="Describe your responsibilities..." />
                    </div>
                  </div>
                </div>
              ))}
              {experience.length === 0 && (
                <div className="text-center py-10 text-gray-600 text-sm">
                  <Briefcase size={32} className="mx-auto mb-2 opacity-40" />
                  No experience entries yet. Click &quot;Add Experience&quot; to get started.
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── Skills ── */}
        {activeTab === 'skills' && (
          <div>
            <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-5">
              <Star size={15} className="text-emerald-400" /> Skills
            </h2>
            {/* Current Skills */}
            <div className="flex flex-wrap gap-2 mb-4">
              {skills.map((s, i) => (
                <span key={s} className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-emerald-500/10 text-emerald-300 border border-emerald-500/20 text-sm font-medium">
                  {s}
                  <button onClick={() => setSkills(p => p.filter((_, idx) => idx !== i))} className="hover:text-rose-400 transition-colors"><X size={11} /></button>
                </span>
              ))}
            </div>
            {/* Add Skill */}
            <div className="flex gap-2 mb-4">
              <input
                type="text"
                value={newSkill}
                onChange={e => setNewSkill(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && addSkill()}
                placeholder="Type a skill and press Enter..."
                className="search-input flex-1 px-3 py-2.5 text-sm bg-[#0e0e22]"
              />
              <button onClick={addSkill} className="px-4 py-2.5 rounded-xl bg-gradient-to-r from-emerald-600 to-cyan-600 text-white text-sm font-semibold hover:opacity-90 transition-opacity">
                <Plus size={15} />
              </button>
            </div>
            {/* Suggestions */}
            <p className="text-xs text-gray-500 mb-2">Suggested skills:</p>
            <div className="flex flex-wrap gap-1.5">
              {SKILL_SUGGESTIONS.filter(s => !skills.includes(s)).slice(0, 8).map(s => (
                <button
                  key={s}
                  onClick={() => setSkills(p => [...p, s])}
                  className="text-xs px-2.5 py-1 rounded-lg bg-white/[0.04] text-gray-400 border border-white/[0.08] hover:border-emerald-500/30 hover:text-emerald-400 transition-all bg-[#0e0e22]"
                >
                  + {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ── Languages ── */}
        {activeTab === 'languages' && (
          <div>
            <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-5">
              <Languages size={15} className="text-emerald-400" /> Languages
            </h2>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
              {LANGUAGE_OPTIONS.map(lang => {
                const isSelected = languages.includes(lang);
                return (
                  <label
                    key={lang}
                    className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all ${
                      isSelected
                        ? 'bg-emerald-500/10 border-emerald-500/25 text-emerald-400'
                        : 'bg-white/[0.02] border-white/[0.06] text-gray-400 hover:border-white/[0.12]'
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={isSelected}
                      onChange={() => {
                        setLanguages(prev =>
                          isSelected ? prev.filter(l => l !== lang) : [...prev, lang]
                        );
                      }}
                      className="hidden"
                    />
                    <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-all ${
                      isSelected ? 'bg-emerald-500 border-emerald-500' : 'border-gray-600'
                    }`}>
                      {isSelected && <Check size={12} className="text-white" />}
                    </div>
                    <span className="text-sm font-medium">{lang}</span>
                  </label>
                );
              })}
            </div>
          </div>
        )}

        {/* ── Certifications ── */}
        {activeTab === 'certifications' && (
          <div>
            <div className="flex items-center justify-between mb-5">
              <h2 className="font-semibold text-white text-sm flex items-center gap-2">
                <Award size={15} className="text-emerald-400" /> Certifications
              </h2>
              <button onClick={addCertification} className="flex items-center gap-1 text-xs text-emerald-400 hover:text-emerald-300 px-3 py-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/20 transition-all">
                <Plus size={12} /> Add Certification
              </button>
            </div>
            <div className="space-y-4">
              {certifications.map(cert => (
                <div key={cert.id} className="p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] relative group">
                  <button onClick={() => removeCertification(cert.id)} className="absolute top-3 right-3 p-1 rounded-lg text-gray-600 hover:text-rose-400 hover:bg-rose-500/10 transition-all opacity-0 group-hover:opacity-100">
                    <X size={14} />
                  </button>
                  <div className="grid sm:grid-cols-2 gap-3">
                    <div>
                      <label className="text-xs text-gray-500 block mb-1">Certification Name</label>
                      <input type="text" value={cert.name} onChange={e => updateCertification(cert.id, 'name', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="e.g. Google Analytics" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-500 block mb-1">Organization</label>
                      <input type="text" value={cert.organization} onChange={e => updateCertification(cert.id, 'organization', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="e.g. Google" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-500 block mb-1">Date</label>
                      <input type="month" value={cert.date} onChange={e => updateCertification(cert.id, 'date', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" />
                    </div>
                    <div>
                      <label className="text-xs text-gray-500 block mb-1">Certificate Link (Optional)</label>
                      <input type="url" value={cert.link} onChange={e => updateCertification(cert.id, 'link', e.target.value)} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="https://..." />
                    </div>
                  </div>
                </div>
              ))}
              {certifications.length === 0 && (
                <div className="text-center py-10 text-gray-600 text-sm">
                  <Award size={32} className="mx-auto mb-2 opacity-40" />
                  No certifications yet. Add your professional certifications.
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── Portfolio ── */}
        {activeTab === 'portfolio' && (
          <div>
            <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-5">
              <Globe size={15} className="text-emerald-400" /> Portfolio & Links
            </h2>
            <div className="space-y-3 mb-4">
              {portfolio.map((link, idx) => (
                <div key={idx} className="flex items-center gap-3 p-3 rounded-xl bg-white/[0.03] border border-white/[0.06] group">
                  <div className="w-9 h-9 rounded-lg bg-cyan-500/10 flex items-center justify-center shrink-0">
                    <ExternalLink size={15} className="text-cyan-400" />
                  </div>
                  <span className="flex-1 text-sm text-cyan-300 truncate">{link}</span>
                  <button
                    onClick={() => setPortfolio(p => p.filter((_, i) => i !== idx))}
                    className="p-1.5 rounded-lg text-gray-600 hover:text-rose-400 hover:bg-rose-500/10 transition-all opacity-0 group-hover:opacity-100"
                  >
                    <X size={13} />
                  </button>
                </div>
              ))}
            </div>
            <div className="flex gap-2">
              <input
                type="url"
                value={newPortfolioLink}
                onChange={e => setNewPortfolioLink(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && addPortfolioLink()}
                placeholder="Add portfolio URL..."
                className="search-input flex-1 px-3 py-2.5 text-sm bg-[#0e0e22]"
              />
              <button onClick={addPortfolioLink} className="px-4 py-2.5 rounded-xl bg-gradient-to-r from-emerald-600 to-cyan-600 text-white text-sm font-semibold hover:opacity-90 transition-opacity">
                <Plus size={15} />
              </button>
            </div>
          </div>
        )}
      </div>

      {/* ═══ Save Button ═══ */}
      <button
        onClick={handleSaveProfile}
        disabled={saving}
        className="w-full py-4 rounded-2xl bg-gradient-to-r from-emerald-600 to-cyan-600 text-white font-semibold text-base hover:opacity-90 transition-opacity flex items-center justify-center gap-2 disabled:opacity-50"
      >
        {saving ? <Loader2 size={18} className="animate-spin text-white" /> : <Save size={18} />}
        {saving ? 'Saving Profile...' : 'Save Profile'}
      </button>
    </div>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import {
  User, GraduationCap, Briefcase, Star, Eye,
  ChevronLeft, ChevronRight, Check, FileText, Sparkles,
  Mail, Phone, MapPin, ArrowLeft, Palette, Loader2
} from 'lucide-react';
import { useAuth } from '@/hooks/useAuth';
import { useDocument } from '@/hooks/useFirestore';
import { db } from '@/lib/firebase/config';
import { setDoc, doc, arrayUnion } from 'firebase/firestore';
import { useRouter } from 'next/navigation';

type Step = 'personal' | 'education' | 'experience' | 'skills' | 'preview';

interface PersonalInfo {
  name: string;
  email: string;
  phone: string;
  address: string;
  district: string;
  summary: string;
}

interface EduEntry {
  id: string;
  institution: string;
  degree: string;
  field: string;
  year: string;
}

interface ExpEntry {
  id: string;
  company: string;
  role: string;
  duration: string;
  description: string;
}

const STEPS: { key: Step; label: string; icon: React.ElementType }[] = [
  { key: 'personal', label: 'Personal Info', icon: User },
  { key: 'education', label: 'Education', icon: GraduationCap },
  { key: 'experience', label: 'Experience', icon: Briefcase },
  { key: 'skills', label: 'Skills', icon: Star },
  { key: 'preview', label: 'Preview', icon: Eye },
];

const TEMPLATES = [
  { id: 'professional', name: 'Professional', desc: 'Clean corporate layout', color: 'from-emerald-500 to-cyan-500' },
  { id: 'modern', name: 'Modern', desc: 'Creative with sidebar', color: 'from-violet-500 to-purple-500' },
  { id: 'simple', name: 'Simple', desc: 'Minimal and elegant', color: 'from-cyan-500 to-blue-500' },
];

export default function ResumeBuilderPage() {
  const { user } = useAuth();
  const router = useRouter();

  // Fetch profile to allow auto-fill
  const { data: profileDoc, loading: profileLoading } = useDocument<any>('seekerProfiles', user?.uid);

  const [currentStep, setCurrentStep] = useState<Step>('personal');
  const [selectedTemplate, setSelectedTemplate] = useState('professional');
  const [saving, setSaving] = useState(false);

  const [personal, setPersonal] = useState<PersonalInfo>({
    name: '', email: '', phone: '', address: '', district: 'Theni',
    summary: '',
  });

  const [education, setEducation] = useState<EduEntry[]>([
    { id: '1', institution: '', degree: '', field: '', year: '' },
  ]);

  const [experience, setExperience] = useState<ExpEntry[]>([
    { id: '1', company: '', role: '', duration: '', description: '' },
  ]);

  const [skills, setSkills] = useState<string[]>([]);
  const [newSkill, setNewSkill] = useState('');

  const stepIndex = STEPS.findIndex(s => s.key === currentStep);
  const progressPercent = ((stepIndex + 1) / STEPS.length) * 100;

  const goNext = () => {
    const idx = STEPS.findIndex(s => s.key === currentStep);
    if (idx < STEPS.length - 1) setCurrentStep(STEPS[idx + 1].key);
  };

  const goPrev = () => {
    const idx = STEPS.findIndex(s => s.key === currentStep);
    if (idx > 0) setCurrentStep(STEPS[idx - 1].key);
  };

  const autoFillFromProfile = () => {
    if (profileDoc) {
      setPersonal({
        name: profileDoc.name || '',
        email: profileDoc.email || '',
        phone: profileDoc.phone || '',
        address: profileDoc.address || '',
        district: profileDoc.district || 'Theni',
        summary: profileDoc.summary || `Motivated ${profileDoc.currentRole || 'Job Seeker'} with experience building professional skills. Based in ${profileDoc.district || 'Theni'}, Tamil Nadu.`
      });
      if (profileDoc.education && profileDoc.education.length > 0) {
        setEducation(profileDoc.education.map((edu: any) => ({
          id: edu.id || Date.now().toString(),
          institution: edu.institution || '',
          degree: edu.degree || '',
          field: edu.field || '',
          year: edu.year || ''
        })));
      }
      if (profileDoc.experience && profileDoc.experience.length > 0) {
        setExperience(profileDoc.experience.map((exp: any) => ({
          id: exp.id || Date.now().toString(),
          company: exp.company || '',
          role: exp.role || '',
          duration: exp.startDate && exp.endDate ? `${exp.startDate} – ${exp.endDate}` : '',
          description: exp.description || ''
        })));
      }
      setSkills(profileDoc.skills || []);
    } else {
      alert('Please fill in your profile page first to use auto-fill.');
    }
  };

  const addSkill = () => {
    if (newSkill.trim() && !skills.includes(newSkill.trim())) {
      setSkills(s => [...s, newSkill.trim()]);
      setNewSkill('');
    }
  };

  const handleSaveResume = async () => {
    if (!user?.uid) return;
    setSaving(true);
    try {
      const resumeData = {
        id: Date.now().toString(),
        name: `${personal.name.replace(/\s+/g, '_') || 'Resume'}_Builder.pdf`,
        uploadDate: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }),
        size: 'Built Online',
        isDefault: false,
        format: 'PDF',
        url: '#', // In production, this would render a PDF and upload to Storage
        content: {
          personal,
          education,
          experience,
          skills,
          template: selectedTemplate
        }
      };

      // Append to the resumes array inside seekerProfiles
      await setDoc(doc(db, 'seekerProfiles', user.uid), {
        resumes: arrayUnion(resumeData)
      }, { merge: true });

      alert('Resume saved successfully in your profile!');
      router.push('/seeker/resume');
    } catch (err) {
      console.error(err);
      alert('Failed to save resume');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="animate-fade-in-up space-y-6 max-w-6xl mx-auto font-outfit text-white">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div className="flex items-center gap-3">
          <Link href="/seeker/resume" className="p-2 rounded-xl bg-white/[0.04] border border-white/[0.06] text-gray-400 hover:text-white hover:bg-white/[0.08] transition-all">
            <ArrowLeft size={16} />
          </Link>
          <div>
            <h1 className="text-xl font-outfit font-bold text-white">Resume Builder</h1>
            <p className="text-sm text-gray-400">Create a professional resume step by step</p>
          </div>
        </div>
        <button
          onClick={autoFillFromProfile}
          className="flex items-center gap-1.5 px-4 py-2 rounded-xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 text-xs font-semibold hover:bg-emerald-500/20 transition-all"
        >
          <Sparkles size={14} /> Auto-fill from Profile
        </button>
      </div>

      {/* Progress Bar */}
      <div className="glass-card rounded-2xl p-5">
        <div className="flex items-center justify-between mb-3">
          {STEPS.map((step, idx) => {
            const Icon = step.icon;
            const isActive = step.key === currentStep;
            const isDone = idx < stepIndex;
            return (
              <button
                key={step.key}
                onClick={() => setCurrentStep(step.key)}
                className="flex flex-col items-center gap-1.5 group flex-1"
              >
                <div className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${
                  isActive
                    ? 'bg-emerald-500/20 border border-emerald-500/30'
                    : isDone
                      ? 'bg-emerald-500/10 border border-emerald-500/15'
                      : 'bg-white/[0.04] border border-white/[0.06]'
                }`}>
                  {isDone ? (
                    <Check size={16} className="text-emerald-400" />
                  ) : (
                    <Icon size={16} className={isActive ? 'text-emerald-400' : 'text-gray-500'} />
                  )}
                </div>
                <span className={`text-[10px] font-medium hidden sm:block ${isActive ? 'text-emerald-400' : isDone ? 'text-gray-400' : 'text-gray-600'}`}>
                  {step.label}
                </span>
              </button>
            );
          })}
        </div>
        <div className="h-1.5 bg-white/[0.06] rounded-full overflow-hidden">
          <div
            className="h-full bg-gradient-to-r from-emerald-500 to-cyan-500 rounded-full transition-all duration-505"
            style={{ width: `${progressPercent}%` }}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-5 gap-6">
        {/* Form Panel */}
        <div className="xl:col-span-3 space-y-6">
          {/* Template Selection */}
          {currentStep === 'personal' && (
            <div className="glass-card rounded-2xl p-5">
              <h3 className="font-semibold text-white text-sm flex items-center gap-2 mb-4">
                <Palette size={15} className="text-emerald-400" /> Choose Template
              </h3>
              <div className="grid grid-cols-3 gap-3">
                {TEMPLATES.map(t => (
                  <button
                    key={t.id}
                    onClick={() => setSelectedTemplate(t.id)}
                    className={`p-3 rounded-xl border text-center transition-all ${
                      selectedTemplate === t.id
                        ? 'border-emerald-500/30 bg-emerald-500/10'
                        : 'border-white/[0.06] bg-white/[0.02] hover:border-white/[0.12]'
                    }`}
                  >
                    <div className={`w-full h-16 rounded-lg bg-gradient-to-br ${t.color} opacity-30 mb-2`} />
                    <p className={`text-xs font-medium ${selectedTemplate === t.id ? 'text-emerald-400' : 'text-gray-300'}`}>{t.name}</p>
                    <p className="text-[10px] text-gray-500 mt-0.5">{t.desc}</p>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Step Content */}
          <div className="glass-card rounded-2xl p-5">
            {/* Personal Info Step */}
            {currentStep === 'personal' && (
              <div>
                <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-5">
                  <User size={15} className="text-emerald-400" /> Personal Information
                </h2>
                <div className="grid sm:grid-cols-2 gap-4">
                  <div className="sm:col-span-2">
                    <label className="text-xs text-gray-400 block mb-1.5">Full Name</label>
                    <input type="text" value={personal.name} onChange={e => setPersonal(p => ({ ...p, name: e.target.value }))} className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]" placeholder="Alagar Swamy" />
                  </div>
                  <div>
                    <label className="text-xs text-gray-400 block mb-1.5">Email</label>
                    <input type="email" value={personal.email} onChange={e => setPersonal(p => ({ ...p, email: e.target.value }))} className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]" placeholder="email@example.com" />
                  </div>
                  <div>
                    <label className="text-xs text-gray-400 block mb-1.5">Phone</label>
                    <input type="tel" value={personal.phone} onChange={e => setPersonal(p => ({ ...p, phone: e.target.value }))} className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]" placeholder="+91 94876 53210" />
                  </div>
                  <div>
                    <label className="text-xs text-gray-400 block mb-1.5">Address</label>
                    <input type="text" value={personal.address} onChange={e => setPersonal(p => ({ ...p, address: e.target.value }))} className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]" placeholder="Gandhi Nagar, Periyakulam" />
                  </div>
                  <div>
                    <label className="text-xs text-gray-400 block mb-1.5">District</label>
                    <input type="text" value={personal.district} onChange={e => setPersonal(p => ({ ...p, district: e.target.value }))} className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22]" placeholder="Theni" />
                  </div>
                  <div className="sm:col-span-2">
                    <label className="text-xs text-gray-400 block mb-1.5">Professional Summary</label>
                    <textarea rows={3} value={personal.summary} onChange={e => setPersonal(p => ({ ...p, summary: e.target.value }))} className="search-input w-full px-3 py-2.5 text-sm bg-[#0e0e22] resize-none" placeholder="Write a brief professional summary..." />
                  </div>
                </div>
              </div>
            )}

            {/* Education Step */}
            {currentStep === 'education' && (
              <div>
                <div className="flex items-center justify-between mb-5">
                  <h2 className="font-semibold text-white text-sm flex items-center gap-2">
                    <GraduationCap size={15} className="text-emerald-400" /> Education
                  </h2>
                  <button onClick={() => setEducation(e => [...e, { id: Date.now().toString(), institution: '', degree: '', field: '', year: '' }])} className="text-xs text-emerald-400 hover:text-emerald-300 px-3 py-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
                    + Add
                  </button>
                </div>
                <div className="space-y-4">
                  {education.map((edu, idx) => (
                    <div key={edu.id} className="p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] relative group">
                      {education.length > 1 && (
                        <button onClick={() => setEducation(e => e.filter(x => x.id !== edu.id))} className="absolute top-2 right-2 p-1 rounded text-gray-600 hover:text-rose-400 opacity-0 group-hover:opacity-100 transition-all">✕</button>
                      )}
                      <div className="grid sm:grid-cols-2 gap-3">
                        <div><label className="text-xs text-gray-500 mb-1 block">Institution</label><input type="text" value={edu.institution} onChange={e => setEducation(prev => prev.map(x => x.id === edu.id ? { ...x, institution: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="College name" /></div>
                        <div><label className="text-xs text-gray-500 mb-1 block">Degree</label><input type="text" value={edu.degree} onChange={e => setEducation(prev => prev.map(x => x.id === edu.id ? { ...x, degree: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="B.Sc" /></div>
                        <div><label className="text-xs text-gray-500 mb-1 block">Field</label><input type="text" value={edu.field} onChange={e => setEducation(prev => prev.map(x => x.id === edu.id ? { ...x, field: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="Computer Science" /></div>
                        <div><label className="text-xs text-gray-500 mb-1 block">Year</label><input type="text" value={edu.year} onChange={e => setEducation(prev => prev.map(x => x.id === edu.id ? { ...x, year: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="2020" /></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Experience Step */}
            {currentStep === 'experience' && (
              <div>
                <div className="flex items-center justify-between mb-5">
                  <h2 className="font-semibold text-white text-sm flex items-center gap-2">
                    <Briefcase size={15} className="text-emerald-400" /> Work Experience
                  </h2>
                  <button onClick={() => setExperience(e => [...e, { id: Date.now().toString(), company: '', role: '', duration: '', description: '' }])} className="text-xs text-emerald-400 hover:text-emerald-300 px-3 py-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
                    + Add
                  </button>
                </div>
                <div className="space-y-4">
                  {experience.map((exp) => (
                    <div key={exp.id} className="p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] relative group">
                      {experience.length > 1 && (
                        <button onClick={() => setExperience(e => e.filter(x => x.id !== exp.id))} className="absolute top-2 right-2 p-1 rounded text-gray-600 hover:text-rose-400 opacity-0 group-hover:opacity-100 transition-all">✕</button>
                      )}
                      <div className="grid sm:grid-cols-2 gap-3">
                        <div><label className="text-xs text-gray-500 mb-1 block">Company</label><input type="text" value={exp.company} onChange={e => setExperience(prev => prev.map(x => x.id === exp.id ? { ...x, company: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="Company name" /></div>
                        <div><label className="text-xs text-gray-500 mb-1 block">Role</label><input type="text" value={exp.role} onChange={e => setExperience(prev => prev.map(x => x.id === exp.id ? { ...x, role: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="Job title" /></div>
                        <div><label className="text-xs text-gray-500 mb-1 block">Duration</label><input type="text" value={exp.duration} onChange={e => setExperience(prev => prev.map(x => x.id === exp.id ? { ...x, duration: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="2022 – Present" /></div>
                        <div><label className="text-xs text-gray-500 mb-1 block">Description</label><input type="text" value={exp.description} onChange={e => setExperience(prev => prev.map(x => x.id === exp.id ? { ...x, description: e.target.value } : x))} className="search-input w-full px-3 py-2 text-sm bg-[#0e0e22]" placeholder="Key responsibilities" /></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Skills Step */}
            {currentStep === 'skills' && (
              <div>
                <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-5">
                  <Star size={15} className="text-emerald-400" /> Skills
                </h2>
                <div className="flex flex-wrap gap-2 mb-4">
                  {skills.map((s, i) => (
                    <span key={s} className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-emerald-500/10 text-emerald-300 border border-emerald-500/20 text-sm font-medium">
                      {s}
                      <button onClick={() => setSkills(p => p.filter((_, idx) => idx !== i))} className="hover:text-rose-400 transition-colors">✕</button>
                    </span>
                  ))}
                  {skills.length === 0 && <p className="text-xs text-gray-600">No skills added yet</p>}
                </div>
                <div className="flex gap-2">
                  <input type="text" value={newSkill} onChange={e => setNewSkill(e.target.value)} onKeyDown={e => e.key === 'Enter' && addSkill()} placeholder="Type a skill..." className="search-input flex-1 px-3 py-2.5 text-sm bg-[#0e0e22]" />
                  <button onClick={addSkill} className="px-4 py-2.5 rounded-xl bg-gradient-to-r from-emerald-600 to-cyan-600 text-white text-sm font-semibold hover:opacity-90 transition-opacity">Add</button>
                </div>
              </div>
            )}

            {/* Preview Step */}
            {currentStep === 'preview' && (
              <div>
                <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-5">
                  <Eye size={15} className="text-emerald-400" /> Preview & Save
                </h2>
                <p className="text-xs text-gray-500 mb-4">Save your compiled resume details to your seeker dashboard profile</p>
                <div className="flex gap-3">
                  <button
                    onClick={handleSaveResume}
                    disabled={saving}
                    className="flex-1 py-3 rounded-xl bg-gradient-to-r from-emerald-600 to-cyan-600 text-white text-sm font-semibold hover:opacity-90 transition-opacity flex items-center justify-center gap-2 disabled:opacity-50"
                  >
                    {saving ? <Loader2 size={16} className="animate-spin text-white" /> : <Check size={16} />}
                    {saving ? 'Saving...' : 'Save & Publish Resume'}
                  </button>
                </div>
              </div>
            )}
          </div>

          {/* Navigation Buttons */}
          <div className="flex items-center justify-between">
            <button
              onClick={goPrev}
              disabled={stepIndex === 0}
              className={`flex items-center gap-1.5 px-4 py-2.5 rounded-xl text-sm font-medium transition-all ${
                stepIndex === 0
                  ? 'text-gray-600 cursor-not-allowed'
                  : 'bg-white/[0.04] border border-white/[0.06] text-gray-300 hover:bg-white/[0.08]'
              }`}
            >
              <ChevronLeft size={16} /> Previous
            </button>
            {stepIndex < STEPS.length - 1 && (
              <button
                onClick={goNext}
                className="flex items-center gap-1.5 px-5 py-2.5 rounded-xl bg-gradient-to-r from-emerald-600 to-cyan-600 text-white text-sm font-semibold hover:opacity-90 transition-opacity"
              >
                Next <ChevronRight size={16} />
              </button>
            )}
          </div>
        </div>

        {/* Live Preview Panel */}
        <div className="xl:col-span-2">
          <div className="glass-card rounded-2xl p-5 sticky top-24">
            <h3 className="font-semibold text-white text-sm flex items-center gap-2 mb-4">
              <Eye size={15} className="text-cyan-400" /> Live Preview
            </h3>
            {/* Simulated Resume Preview */}
            <div className="bg-white rounded-xl p-5 min-h-[500px] text-gray-900">
              {/* Name */}
              <div className="text-center border-b border-gray-200 pb-3 mb-3">
                <h2 className="text-lg font-bold text-gray-900">
                  {personal.name || 'Your Name'}
                </h2>
                <div className="flex items-center justify-center gap-3 mt-1 text-[10px] text-gray-500 flex-wrap">
                  {personal.email && <span className="flex items-center gap-0.5"><Mail size={8} /> {personal.email}</span>}
                  {personal.phone && <span className="flex items-center gap-0.5"><Phone size={8} /> {personal.phone}</span>}
                  {personal.district && <span className="flex items-center gap-0.5"><MapPin size={8} /> {personal.district}</span>}
                </div>
              </div>

              {/* Summary */}
              {personal.summary && (
                <div className="mb-3">
                  <h4 className="text-[10px] font-bold text-gray-700 uppercase tracking-wider mb-1">Summary</h4>
                  <p className="text-[9px] text-gray-600 leading-relaxed">{personal.summary}</p>
                </div>
              )}

              {/* Education */}
              {education.some(e => e.institution) && (
                <div className="mb-3">
                  <h4 className="text-[10px] font-bold text-gray-700 uppercase tracking-wider mb-1">Education</h4>
                  {education.filter(e => e.institution).map(edu => (
                    <div key={edu.id} className="mb-1.5">
                      <p className="text-[9px] font-semibold text-gray-800">{edu.degree} {edu.field && `in ${edu.field}`}</p>
                      <p className="text-[8px] text-gray-505">{edu.institution} {edu.year && `• ${edu.year}`}</p>
                    </div>
                  ))}
                </div>
              )}

              {/* Experience */}
              {experience.some(e => e.company) && (
                <div className="mb-3">
                  <h4 className="text-[10px] font-bold text-gray-700 uppercase tracking-wider mb-1">Experience</h4>
                  {experience.filter(e => e.company).map(exp => (
                    <div key={exp.id} className="mb-1.5">
                      <p className="text-[9px] font-semibold text-gray-800">{exp.role} — {exp.company}</p>
                      <p className="text-[8px] text-gray-505">{exp.duration}</p>
                      {exp.description && <p className="text-[8px] text-gray-600 mt-0.5">{exp.description}</p>}
                    </div>
                  ))}
                </div>
              )}

              {/* Skills */}
              {skills.length > 0 && (
                <div>
                  <h4 className="text-[10px] font-bold text-gray-700 uppercase tracking-wider mb-1">Skills</h4>
                  <div className="flex flex-wrap gap-1">
                    {skills.map(s => (
                      <span key={s} className="text-[8px] px-1.5 py-0.5 rounded bg-gray-100 text-gray-600">{s}</span>
                    ))}
                  </div>
                </div>
              )}

              {/* Empty State */}
              {!personal.name && education.every(e => !e.institution) && experience.every(e => !e.company) && skills.length === 0 && (
                <div className="flex flex-col items-center justify-center py-16 text-gray-300">
                  <FileText size={32} className="mb-2" />
                  <p className="text-xs">Fill in the form to see your resume preview</p>
                  <p className="text-[10px] text-gray-400 mt-1">or click &quot;Auto-fill from Profile&quot;</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useRef, useCallback } from 'react';
import Link from 'next/link';
import {
  Upload, FileText, Download, Trash2, Star, CheckCircle,
  File, Clock, Zap, ChevronRight, Lightbulb, Shield,
  HardDrive, Eye, Loader2
} from 'lucide-react';
import { useAuth } from '@/hooks/useAuth';
import { useDocument } from '@/hooks/useFirestore';
import { useUploadFile, useDeleteFile } from '@/hooks/useStorage';
import { db } from '@/lib/firebase/config';
import { doc, setDoc } from 'firebase/firestore';

interface ResumeFile {
  id: string;
  name: string;
  uploadDate: string;
  size: string;
  isDefault: boolean;
  format: string;
  url?: string;
  storagePath?: string;
}

export default function ResumeManagementPage() {
  const { user } = useAuth();
  const uid = user?.uid;

  // 1. Fetch seekerProfile to get resumes list in real-time
  const { data: seekerProfile, loading: profileLoading } = useDocument<any>('seekerProfiles', uid);
  const resumes: ResumeFile[] = seekerProfile?.resumes || [];

  const { uploadFile, progress: uploadProgress, loading: uploading } = useUploadFile();
  const { deleteFile } = useDeleteFile();
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback(() => {
    setIsDragging(false);
  }, []);

  const saveResumesToDb = async (newResumes: ResumeFile[]) => {
    if (!uid) return;
    try {
      await setDoc(doc(db, 'seekerProfiles', uid), {
        resumes: newResumes
      }, { merge: true });
    } catch (err) {
      console.error('Failed to save resumes:', err);
      alert('Failed to update resumes list.');
    }
  };

  const handleUpload = async (file: File) => {
    if (!uid) return;
    try {
      const timestamp = Date.now();
      const storagePath = `resumes/${uid}/${timestamp}_${file.name}`;
      const downloadUrl = await uploadFile(file, storagePath, {
        allowedTypes: ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'],
        maxSizeBytes: 5 * 1024 * 1024
      });

      const newResume: ResumeFile = {
        id: timestamp.toString(),
        name: file.name,
        uploadDate: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }),
        size: `${(file.size / 1024).toFixed(0)} KB`,
        isDefault: resumes.length === 0,
        format: file.name.split('.').pop()?.toUpperCase() || 'PDF',
        url: downloadUrl,
        storagePath: storagePath
      };

      await saveResumesToDb([...resumes, newResume]);
    } catch (err) {
      console.error(err);
      alert('Upload failed: ' + (err as Error).message);
    }
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) {
      handleUpload(file);
    }
  }, [resumes, uid]);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleUpload(file);
    }
  };

  const setAsDefault = async (id: string) => {
    const updated = resumes.map(r => ({ ...r, isDefault: r.id === id }));
    await saveResumesToDb(updated);
  };

  const handleDeleteResume = async (resume: ResumeFile) => {
    if (!confirm(`Are you sure you want to delete "${resume.name}"?`)) return;

    if (resume.storagePath) {
      try {
        await deleteFile(resume.storagePath);
      } catch (err) {
        console.error('Failed to delete storage file:', err);
      }
    }

    const updated = resumes.filter(r => r.id !== resume.id);
    if (resume.isDefault && updated.length > 0) {
      updated[0].isDefault = true;
    }
    await saveResumesToDb(updated);
  };

  return (
    <div className="animate-fade-in-up space-y-6 max-w-4xl mx-auto font-outfit text-white">
      {/* Page Header */}
      <div>
        <h1 className="text-xl font-outfit font-bold text-white">Resume Management</h1>
        <p className="text-sm text-gray-400 mt-1">Upload, manage, and build your professional resume</p>
      </div>

      {uploading && (
        <div className="glass-card rounded-2xl p-4 border border-emerald-500/20 bg-emerald-500/5 flex items-center gap-3">
          <Loader2 size={18} className="text-emerald-400 animate-spin" />
          <span className="text-xs text-gray-300">Uploading resume... {uploadProgress}%</span>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column - Main Content */}
        <div className="lg:col-span-2 space-y-6">
          {/* Upload Resume Zone */}
          <div className="glass-card rounded-2xl p-5">
            <h2 className="font-semibold text-white text-sm flex items-center gap-2 mb-4">
              <Upload size={15} className="text-emerald-400" /> Upload Resume
            </h2>
            <div
              onDragOver={handleDragOver}
              onDragLeave={handleDragLeave}
              onDrop={handleDrop}
              onClick={() => fileInputRef.current?.click()}
              className={`flex flex-col items-center justify-center gap-3 p-8 rounded-xl border-2 border-dashed cursor-pointer transition-all ${
                isDragging
                  ? 'border-emerald-500/60 bg-emerald-500/10'
                  : 'border-white/15 hover:border-emerald-500/40 hover:bg-emerald-500/5'
              }`}
            >
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-colors ${
                isDragging ? 'bg-emerald-500/20' : 'bg-white/[0.06]'
              }`}>
                <Upload size={24} className={isDragging ? 'text-emerald-400' : 'text-gray-400'} />
              </div>
              <div className="text-center">
                <p className="text-sm font-medium text-white">
                  {isDragging ? 'Drop your resume here' : 'Drag & drop your resume here'}
                </p>
                <p className="text-xs text-gray-505 mt-1">
                  or <span className="text-emerald-400 font-medium">browse files</span> — PDF, DOC (max 5MB)
                </p>
              </div>
              <input
                ref={fileInputRef}
                type="file"
                accept=".pdf,.doc,.docx"
                className="hidden"
                onChange={handleFileSelect}
              />
            </div>
          </div>

          {/* Resume Versions List */}
          <div className="glass-card rounded-2xl overflow-hidden">
            <div className="flex items-center justify-between px-5 py-4 border-b border-white/[0.06]">
              <h2 className="font-semibold text-white text-sm flex items-center gap-2">
                <FileText size={15} className="text-emerald-400" /> My Resumes
              </h2>
              <span className="text-xs text-gray-505">{resumes.length} resume{resumes.length !== 1 ? 's' : ''}</span>
            </div>

            {profileLoading ? (
              <div className="flex flex-col items-center justify-center py-12">
                <Loader2 size={24} className="text-emerald-400 animate-spin mb-2" />
                <p className="text-xs text-gray-505">Loading resumes...</p>
              </div>
            ) : (
              <div className="divide-y divide-white/[0.04]">
                {resumes.map(resume => (
                  <div key={resume.id} className="flex items-center gap-4 px-5 py-4 hover:bg-white/[0.02] transition-colors group">
                    {/* File Icon */}
                    <div className={`w-11 h-11 rounded-xl flex items-center justify-center shrink-0 ${
                      resume.isDefault
                        ? 'bg-emerald-500/15 border border-emerald-500/20'
                        : 'bg-white/[0.04] border border-white/[0.06]'
                    }`}>
                      <File size={20} className={resume.isDefault ? 'text-emerald-400' : 'text-gray-400'} />
                    </div>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-medium text-white truncate">{resume.name}</p>
                        {resume.isDefault && (
                          <span className="text-[9px] px-2 py-0.5 rounded-full bg-emerald-500/15 text-emerald-400 border border-emerald-500/20 font-bold uppercase">
                            Default
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-3 mt-1 text-[11px] text-gray-505">
                        <span className="flex items-center gap-1"><Clock size={10} /> {resume.uploadDate}</span>
                        <span className="flex items-center gap-1"><HardDrive size={10} /> {resume.size}</span>
                        <span className="uppercase font-medium text-gray-600">{resume.format}</span>
                      </div>
                    </div>

                    {/* Actions */}
                    <div className="flex items-center gap-1.5 shrink-0">
                      {!resume.isDefault && (
                        <button
                          onClick={() => setAsDefault(resume.id)}
                          className="p-2 rounded-lg text-gray-500 hover:text-emerald-400 hover:bg-emerald-500/10 transition-all"
                          title="Set as Default"
                        >
                          <Star size={14} />
                        </button>
                      )}
                      {resume.url && resume.url !== '#' && (
                        <>
                          <button
                            onClick={() => window.open(resume.url, '_blank')}
                            className="p-2 rounded-lg text-gray-500 hover:text-cyan-400 hover:bg-cyan-500/10 transition-all"
                            title="Preview"
                          >
                            <Eye size={14} />
                          </button>
                          <a
                            href={resume.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="p-2 rounded-lg text-gray-500 hover:text-white hover:bg-white/[0.08] transition-all"
                            title="Download"
                          >
                            <Download size={14} />
                          </a>
                        </>
                      )}
                      <button
                        onClick={() => handleDeleteResume(resume)}
                        className="p-2 rounded-lg text-gray-500 hover:text-rose-400 hover:bg-rose-500/10 transition-all"
                        title="Delete"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </div>
                ))}
                {resumes.length === 0 && (
                  <div className="text-center py-12 text-gray-600">
                    <FileText size={36} className="mx-auto mb-3 opacity-30" />
                    <p className="text-sm">No resumes uploaded yet</p>
                    <p className="text-xs mt-1">Upload your first resume to get started</p>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Resume Builder CTA */}
          <Link
            href="/seeker/resume/builder"
            className="glass-card rounded-2xl p-5 flex items-center gap-4 hover:border-emerald-500/20 transition-all group block"
          >
            <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-emerald-500/20 to-cyan-500/20 flex items-center justify-center shrink-0 group-hover:scale-105 transition-transform">
              <Zap size={24} className="text-emerald-400" />
            </div>
            <div className="flex-1">
              <h3 className="text-sm font-semibold text-white group-hover:text-emerald-400 transition-colors">
                Build Resume Online
              </h3>
              <p className="text-xs text-gray-450 mt-0.5">
                Use our step-by-step builder to create a professional resume. Choose from 3 templates.
              </p>
              <div className="flex items-center gap-3 mt-2">
                {['Professional', 'Modern', 'Simple'].map(t => (
                  <span key={t} className="text-[10px] px-2 py-0.5 rounded-lg bg-white/[0.04] text-gray-400 border border-white/[0.06]">
                    {t}
                  </span>
                ))}
              </div>
            </div>
            <ChevronRight size={18} className="text-gray-600 group-hover:text-emerald-400 transition-colors shrink-0" />
          </Link>
        </div>

        {/* Right Column - Tips */}
        <div className="space-y-6">
          {/* Resume Tips */}
          <div className="glass-card rounded-2xl p-5">
            <h3 className="font-semibold text-white text-sm flex items-center gap-2 mb-4">
              <Lightbulb size={15} className="text-amber-400" /> Resume Tips
            </h3>
            <div className="space-y-3">
              {[
                { tip: 'Keep your resume to 1-2 pages for better readability', icon: FileText },
                { tip: 'Use keywords from job descriptions to pass ATS scans', icon: Shield },
                { tip: 'Quantify achievements with numbers and percentages', icon: Star },
                { tip: 'Update your resume every 3-6 months', icon: Clock },
                { tip: 'Use a professional email address', icon: CheckCircle },
              ].map((item, idx) => {
                const Icon = item.icon;
                return (
                  <div key={idx} className="flex items-start gap-2.5">
                    <div className="w-6 h-6 rounded-lg bg-amber-500/10 flex items-center justify-center shrink-0 mt-0.5">
                      <Icon size={11} className="text-amber-400" />
                    </div>
                    <p className="text-xs text-gray-400 leading-relaxed">{item.tip}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Quick Stats */}
          <div className="glass-card rounded-2xl p-5">
            <h3 className="font-semibold text-white text-sm mb-4">Resume Stats</h3>
            <div className="space-y-3">
              {[
                { label: 'Total Resumes', value: resumes.length.toString(), color: 'text-emerald-400' },
